{
  "name": "RunCertify - Marathon Certificate System",
  "description": "A high-end marathon certificate generation platform allowing race organizers to design and generate professional finisher certificates with AI-enhanced inspirational quotes and custom badge designs."
}

export enum RaceCategory {
  FULL = 'Full Marathon (42.195km)',
  HALF = 'Half Marathon (21.0975km)',
  TEN_K = '10K Run',
  FIVE_K = '5K Fun Run'
}

export interface FinisherData {
  id: string;
  name: string;
  bibNumber: string;
  raceName: string;
  category: RaceCategory;
  finishTime: string; // HH:MM:SS
  netTime: string;
  genderRank: string;
  overallRank: string;
  date: string;
  inspirationalQuote?: string;
  badgeImageUrl?: string;
}

export interface CertificateStyle {
  template: 'classic' | 'modern' | 'minimal' | 'energetic';
  primaryColor: string;
  secondaryColor: string;
  backgroundImage?: string;
}

export type AppView = 'dashboard' | 'editor' | 'preview';

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateInspirationalQuote(name: string, category: string, finishTime: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create a short, powerful, and unique inspirational quote for a marathon finisher named ${name} who completed the ${category} in ${finishTime}. The quote should be in English, focused on resilience, achievement, and the spirit of running. Keep it under 20 words.`,
      config: {
        temperature: 0.8,
        topP: 0.9,
      }
    });
    return response.text || "Your limit is only your imagination.";
  } catch (error) {
    console.error("Error generating quote:", error);
    return "The race is not for the swift, but for those who keep running.";
  }
}

export async function generateCustomBadge(theme: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A high-quality, circular vector badge for a marathon achievement. Theme: ${theme}. Minimalist design, gold and professional colors, white background, 4k resolution.` }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating badge:", error);
    return null;
  }
}

