export type Language = 'zh' | 'en';

export interface FinisherData {
  id: string;
  name: string;
  bibNumber: string;
  raceName: string;
  category: string; // Changed from Enum to string for flexibility
  finishTime: string; // HH:MM:SS
  netTime: string;
  genderRank: string;
  overallRank: string;
  date: string;
  inspirationalQuote?: string;
  badgeImageUrl?: string;
  logoUrl?: string; // Support for race logo
}

export interface CertificateStyle {
  template: 'classic' | 'modern' | 'minimal' | 'energetic';
  primaryColor: string;
  secondaryColor: string;
  backgroundImage?: string;
  language: Language; // Support for language switching
}

export type AppView = 'dashboard' | 'editor' | 'preview';

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateInspirationalQuote(name: string, category: string, finishTime: string, lang: 'zh' | 'en') {
  try {
    const prompt = lang === 'zh' 
      ? `为一位名叫 ${name} 的跑者创作一句简短、充满力量且独特的马拉松完赛感言。他完成了 ${category} 比赛，成绩为 ${finishTime}。感言应侧重于坚韧、成就感和跑步精神。字数控制在20字以内。`
      : `Create a short, powerful, and unique inspirational quote for a marathon finisher named ${name} who completed the ${category} in ${finishTime}. The quote should be in English, focused on resilience, achievement, and the spirit of running. Keep it under 20 words.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.8,
        topP: 0.9,
      }
    });
    return response.text || (lang === 'zh' ? "你的极限仅存在于你的想象中。" : "Your limit is only your imagination.");
  } catch (error) {
    console.error("Error generating quote:", error);
    return lang === 'zh' ? "比赛不只属于最快的人，也属于坚持到底的人。" : "The race is not for the swift, but for those who keep running.";
  }
}

export async function generateCustomBadge(theme: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A high-quality, circular vector badge for a marathon achievement. Theme: ${theme}. Minimalist design, gold and professional colors, white background, 4k resolution.` }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating badge:", error);
    return null;
  }
}

