const App: React.FC = () => {
  const [view, setView] = useState<AppView>('dashboard');
  const [finishers, setFinishers] = useState<FinisherData[]>([INITIAL_DATA]);
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(INITIAL_DATA);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('极速抽象');
  const logoInputRef = useRef<HTMLInputElement>(null);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, logoUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const quote = await generateInspirationalQuote(
        selectedFinisher.name, 
        selectedFinisher.category, 
        selectedFinisher.finishTime,
        style.language
      );
      const badge = await generateCustomBadge(badgeTheme);

      setSelectedFinisher(prev => ({ 
        ...prev, 
        inspirationalQuote: quote, 
        badgeImageUrl: badge || prev.badgeImageUrl 
      }));
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {view !== 'preview' && <Header currentView={view} setView={setView} />}
      <main className="flex-1 bg-slate-50/50">
        {view === 'dashboard' && (
          <DashboardView 
            finishers={finishers} 
            setView={setView} 
            setSelectedFinisher={setSelectedFinisher} 
          />
        )}
        {view === 'editor' && (
          <EditorView 
            selectedFinisher={selectedFinisher}
            setSelectedFinisher={setSelectedFinisher}
            style={style}
            setStyle={setStyle}
            badgeTheme={badgeTheme}
            setBadgeTheme={setBadgeTheme}
            isGenerating={isGenerating}
            handleGenerateAI={handleGenerateAI}
            handleLogoUpload={handleLogoUpload}
            logoInputRef={logoInputRef}
            setView={setView}
            setFinishers={setFinishers}
          />
        )}
        {view === 'preview' && (
          <div className="min-h-screen bg-slate-100 p-8 flex flex-col items-center">
            <div className="w-full max-w-5xl flex justify-between items-center mb-8 no-print">
              <button 
                onClick={() => setView('editor')}
                className="flex items-center gap-2 text-slate-500 font-bold hover:text-slate-800 transition-colors"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                返回编辑
              </button>
              <div className="flex gap-4">
                <button 
                  onClick={() => window.print()}
                  className="bg-slate-900 text-white px-6 py-2 rounded-xl font-bold flex items-center gap-2 hover:bg-slate-800 shadow-lg"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><path d="M6 9V4a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v5"/><rect x="6" y="14" width="12" height="8" rx="1"/></svg>
                  打印 / 存为PDF
                </button>
              </div>
            </div>
            <div className="bg-white p-12 rounded-lg shadow-2xl">
              <Certificate data={selectedFinisher} style={style} />
            </div>
          </div>
        )}
      </main>

      {view !== 'preview' && (
        <footer className="bg-white border-t border-slate-100 py-8 no-print">
          <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-slate-400 text-sm font-medium">© 2024 RunCertify - 专业马拉松完赛证书生成系统</p>
          </div>
        </footer>
      )}
    </div>
  );
};

