                {selectedFinisher.themeImageUrl && (
                  <div className="flex items-center gap-2 bg-slate-50 p-1.5 rounded-xl border border-slate-200 justify-between">
                    <img src={selectedFinisher.themeImageUrl} className="h-6 w-6 object-cover rounded shadow-sm" />
                    <button onClick={() => setSelectedFinisher({...selectedFinisher, themeImageUrl: undefined})} className="text-red-400 p-1"><svg width="14" height="14" fill="currentColor" viewBox="0 0 24 24"><path d="M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z"/></svg></button>
                  </div>
                )}
                <input ref={themeInputRef} type="file" accept="image/*" onChange={handleThemeImageUpload} className="hidden" />
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100">
        <h2 className="text-xl font-black mb-6 flex items-center gap-2 text-indigo-600">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
          AI 智能赋能
        </h2>
        <div className="space-y-4">
          <div>
            <label className="text-xs font-black text-slate-400 uppercase block mb-1">完赛勋章描述</label>
            <input 
              type="text" 
              value={badgeTheme}
              onChange={e => setBadgeTheme(e.target.value)}
