        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100">
        <h2 className="text-xl font-black mb-6">视觉风格控制</h2>

        <div className="mb-4">
          <label className="text-xs font-black text-slate-400 uppercase block mb-2">页面方向 (适配社交分享)</label>
          <div className="flex gap-3">
            <button 
              onClick={() => setStyle({...style, orientation: 'landscape'})}
              className={`flex-1 py-3 rounded-2xl text-xs font-black border-4 transition-all ${style.orientation === 'landscape' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}
            >
              横屏 (16:9)
            </button>
            <button 
              onClick={() => setStyle({...style, orientation: 'portrait'})}
              className={`flex-1 py-3 rounded-2xl text-xs font-black border-4 transition-all ${style.orientation === 'portrait' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}
            >
              竖屏 (9:16)
            </button>
          </div>
        </div>

        <div className="mb-6">
          <label className="text-xs font-black text-slate-400 uppercase block mb-2">语言版本</label>
          <div className="flex gap-3">
            <button 
              onClick={() => setStyle({...style, language: 'zh'})}
              className={`flex-1 py-3 rounded-2xl text-xs font-black border-4 transition-all ${style.language === 'zh' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}
            >
              中文
            </button>
