              onClick={() => setStyle({...style, language: 'en'})}
              className={`flex-1 py-3 rounded-2xl text-xs font-black border-4 transition-all ${style.language === 'en' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}
