              className={`p-4 rounded-2xl border-4 transition-all text-sm font-black capitalize ${style.template === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-50 bg-slate-50 text-slate-400 hover:border-slate-200'}`}
            >
              {t === 'classic' ? '经典商务' : t === 'modern' ? '现代简约' : '动感炫酷'}
