        <div className={`${style.orientation === 'portrait' ? 'scale-[0.5]' : 'scale-[0.6]'} origin-center sm:${style.orientation === 'portrait' ? 'scale-[0.6]' : 'scale-100'} transition-all duration-500`}>
          <Certificate data={selectedFinisher} style={style} />
