          onClick={() => setView('preview')}
          className="px-10 py-4 bg-slate-900 text-white font-black rounded-[20px] hover:bg-slate-800 transition-all shadow-xl active:scale-95"
        >
          查看最终大图
        </button>
        <button 
          onClick={() => {
            setFinishers(prev => {
              const existing = prev.find(f => f.id === selectedFinisher.id);
              if (existing) return prev.map(f => f.id === selectedFinisher.id ? selectedFinisher : f);
              return [...prev, selectedFinisher];
            });
            setView('dashboard');
          }}
          className="px-10 py-4 bg-indigo-600 text-white font-black rounded-[20px] hover:bg-indigo-700 transition-all shadow-xl active:scale-95"
        >
