const App: React.FC = () => {
  const [view, setView] = useState<AppView>('dashboard');
  const [finishers, setFinishers] = useState<FinisherData[]>([INITIAL_DATA]);
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(INITIAL_DATA);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('专业马拉松');

  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, logoUrl: reader.result as string }));
        if (logoInputRef.current) logoInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleThemeImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, themeImageUrl: reader.result as string }));
        if (themeInputRef.current) themeInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const quote = await generateInspirationalQuote(
        selectedFinisher.name, 
        selectedFinisher.category, 
        selectedFinisher.finishTime,
        style.language
      );
      const badge = await generateCustomBadge(badgeTheme);

      setSelectedFinisher(prev => ({ 
        ...prev, 
        inspirationalQuote: quote, 
        badgeImageUrl: badge || prev.badgeImageUrl 
      }));
    } catch (err) {
      console.error("AI Generation failed", err);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-100">
      {view !== 'preview' && <Header currentView={view} setView={setView} />}
      <main className="flex-1 bg-slate-50/50">
        {view === 'dashboard' && (
          <DashboardView 
            finishers={finishers} 
            setView={setView} 
            setSelectedFinisher={setSelectedFinisher} 
          />
        )}
        {view === 'editor' && (
          <EditorView 
            selectedFinisher={selectedFinisher}
            setSelectedFinisher={setSelectedFinisher}
            style={style}
            setStyle={setStyle}
            badgeTheme={badgeTheme}
            setBadgeTheme={setBadgeTheme}
            isGenerating={isGenerating}
            handleGenerateAI={handleGenerateAI}
            handleLogoUpload={handleLogoUpload}
            handleThemeImageUpload={handleThemeImageUpload}
            logoInputRef={logoInputRef}
            themeInputRef={themeInputRef}
            setView={setView}
            setFinishers={setFinishers}
          />
        )}
        {view === 'preview' && (
          <div className="min-h-screen bg-slate-100 p-8 flex flex-col items-center">
            <div className="w-full max-w-5xl flex justify-between items-center mb-8 no-print">
              <button 
                onClick={() => setView('editor')}
                className="flex items-center gap-2 text-slate-600 font-black hover:text-slate-900 transition-colors bg-white px-5 py-2.5 rounded-2xl shadow-sm"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                返回继续编辑
              </button>
              <div className="flex gap-4">
                <button 
                  onClick={() => window.print()}
                  className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black flex items-center gap-2 hover:bg-indigo-700 shadow-xl transition-all"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><path d="M6 9V4a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v5"/><rect x="6" y="14" width="12" height="8" rx="1"/></svg>
                  立即下载 / 打印
                </button>
              </div>
            </div>
            <div className="bg-white p-1 rounded-2xl shadow-[0_40px_100px_-20px_rgba(0,0,0,0.4)] transition-all">
              <Certificate data={selectedFinisher} style={style} />
            </div>
            <p className="mt-8 text-slate-400 text-sm font-bold no-print uppercase tracking-widest">RunCertify Official Finisher Document</p>
          </div>
        )}
      </main>

      {view !== 'preview' && (
        <footer className="bg-white border-t border-slate-100 py-10 no-print">
          <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-slate-400 text-xs font-black uppercase tracking-[0.2em]">RunCertify © 2024 Professional Marathon Solution</p>
          </div>
        </footer>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { FinisherData, CertificateStyle } from '../types';

interface CertificateProps {
  data: FinisherData;
  style: CertificateStyle;
  innerRef?: React.RefObject<HTMLDivElement | null>;
}

const Certificate: React.FC<CertificateProps> = ({ data, style, innerRef }) => {
  const isZh = style.language === 'zh';
  const isPortrait = style.orientation === 'portrait';

  // Dimensions for 16:9 (Landscape) and 9:16 (Portrait)
  const containerStyle = isPortrait 
    ? { width: '450px', height: '800px' } 
    : { width: '800px', height: '450px' };

  const t = {
    title: isZh ? '完赛证书' : 'OFFICIAL FINISHER CERTIFICATE',
    subtitle: isZh ? '兹证明' : 'This is to certify that',
    completion: isZh ? '成功完成了' : 'Successfully completed the',
    bib: isZh ? '参赛号码' : 'Bib Number',
    gunTime: isZh ? '枪声成绩' : 'Gun Time',
    netTime: isZh ? '净计时成绩' : 'Net Time',
    rank: isZh ? '综合排名' : 'Overall Rank',
    director: isZh ? '赛事总监' : 'Race Director',
