const App: React.FC = () => {
  const [view, setView] = useState<AppView>('dashboard');
  const [finishers, setFinishers] = useState<FinisherData[]>([INITIAL_DATA]);
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(INITIAL_DATA);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('专业金牌');

  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);
  const runnerInputRef = useRef<HTMLInputElement>(null);
  const certificateRef = useRef<HTMLDivElement>(null);
  const previewCertificateRef = useRef<HTMLDivElement>(null);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, logoUrl: reader.result as string }));
        if (logoInputRef.current) logoInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleThemeImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, themeImageUrl: reader.result as string }));
        if (themeInputRef.current) themeInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRunnerImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, runnerImageUrl: reader.result as string }));
        if (runnerInputRef.current) runnerInputRef.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const quote = await generateInspirationalQuote(
        selectedFinisher.name, 
        selectedFinisher.category, 
        selectedFinisher.finishTime,
        style.language
      );
      const badge = await generateCustomBadge(badgeTheme);

      setSelectedFinisher(prev => ({ 
        ...prev, 
        inspirationalQuote: quote, 
        badgeImageUrl: badge || prev.badgeImageUrl 
      }));
    } catch (err) {
      console.error("AI Generation failed", err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = async () => {
    const ref = view === 'editor' ? certificateRef : previewCertificateRef;
    if (!ref.current) return;

    setIsDownloading(true);
    try {
      const dataUrl = await htmlToImage.toPng(ref.current, { quality: 1.0, pixelRatio: 2 });
      const link = document.createElement('a');
      link.download = `${selectedFinisher.name}_RunCertify_Certificate.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Download failed', err);
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-100">
      {view !== 'preview' && <Header currentView={view} setView={setView} />}
      <main className="flex-1 bg-slate-50/50">
        {view === 'dashboard' && (
          <DashboardView 
            finishers={finishers} 
            setView={setView} 
            setSelectedFinisher={setSelectedFinisher} 
          />
        )}
        {view === 'editor' && (
          <EditorView 
            selectedFinisher={selectedFinisher}
            setSelectedFinisher={setSelectedFinisher}
            style={style}
            setStyle={setStyle}
            badgeTheme={badgeTheme}
            setBadgeTheme={setBadgeTheme}
            isGenerating={isGenerating}
            handleGenerateAI={handleGenerateAI}
            handleLogoUpload={handleLogoUpload}
            handleThemeImageUpload={handleThemeImageUpload}
            handleRunnerImageUpload={handleRunnerImageUpload}
            logoInputRef={logoInputRef}
            themeInputRef={themeInputRef}
            runnerInputRef={runnerInputRef}
            setView={setView}
            setFinishers={setFinishers}
            certificateRef={certificateRef}
          />
        )}
        {view === 'preview' && (
          <div className="min-h-screen bg-slate-100 p-8 flex flex-col items-center">
            <div className="w-full max-w-5xl flex justify-between items-center mb-8 no-print">
              <button onClick={() => setView('editor')} className="flex items-center gap-2 text-slate-600 font-black hover:text-slate-900 transition-colors bg-white px-5 py-2.5 rounded-2xl shadow-sm">
                <svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="3" viewBox="0 0 24 24"><path d="m15 18-6-6 6-6"/></svg>
                返回继续编辑
              </button>
              <div className="flex gap-4">
                <button disabled={isDownloading} onClick={handleDownload} className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black flex items-center gap-2 hover:bg-indigo-700 shadow-xl transition-all disabled:opacity-50">
                  {isDownloading ? '正在生成图片...' : '下载高清证书'}
                </button>
                <button onClick={() => window.print()} className="bg-slate-900 text-white px-8 py-3 rounded-2xl font-black flex items-center gap-2 hover:bg-slate-800 shadow-xl transition-all">
                  直接打印
                </button>
              </div>
            </div>
            <div className="bg-white p-1 rounded-2xl shadow-2xl transition-all">
              <Certificate data={selectedFinisher} style={style} innerRef={previewCertificateRef} />
            </div>
          </div>
        )}
      </main>

      {view !== 'preview' && (
        <footer className="bg-white border-t border-slate-100 py-10 no-print">
          <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-slate-400 text-xs font-black uppercase tracking-[0.2em]">RunCertify © 2024 Professional Marathon Solution</p>
          </div>
        </footer>
      )}
    </div>
  );
};

export default App;

