const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [view, setView] = useState<AppView>('dashboard');
  const [finishers, setFinishers] = useState<FinisherData[]>(() => {
    const saved = localStorage.getItem('runcertify_records');
    return saved ? JSON.parse(saved) : REPOSITORY_DATA;
  });
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(finishers[0]);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('专业金牌');

  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);
  const runnerInputRef = useRef<HTMLInputElement>(null);
  const certificateRef = useRef<HTMLDivElement>(null);
  const previewCertificateRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem('runcertify_records', JSON.stringify(finishers));
  }, [finishers]);

  const handleExportData = () => {
    const dataStr = JSON.stringify(finishers, null, 2);
    const blob = new Blob([`// 将此数据粘贴回代码的 REPOSITORY_DATA 数组中\nconst EXPORTED_DATA = ${dataStr};`], { type: 'text/javascript' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `runcertify_backup_${new Date().toISOString().split('T')[0]}.js`;
    link.click();
    alert("数据存档包已生成。如果您想在下次部署后依然保留这些数据，请将文件中的内容同步回代码库。");
  };

  const handleSave = () => {
    setFinishers(prev => {
      const idx = prev.findIndex(f => f.id === selectedFinisher.id);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = selectedFinisher;
        return next;
      }
      return [selectedFinisher, ...prev];
    });
    setView('dashboard');
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const [quote, badge] = await Promise.all([
        generateInspirationalQuote(selectedFinisher.name, selectedFinisher.category, selectedFinisher.finishTime, style.language),
        generateCustomBadge(badgeTheme)
      ]);
      setSelectedFinisher(prev => ({ ...prev, inspirationalQuote: quote, badgeImageUrl: badge || prev.badgeImageUrl }));
    } catch (err) {
      console.error(err);
    } finally { setIsGenerating(false); }
  };

  const onFileUpload = (ref: any, field: string) => (e: any) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, [field]: reader.result as string }));
        if (ref.current) ref.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  if (!isLoggedIn) return <LoginView onLogin={() => setIsLoggedIn(true)} />;

  return (
    <div className="min-h-screen flex flex-col bg-slate-50/50">
      {view !== 'preview' && <Header currentView={view} setView={setView} />}
      <main className="flex-1">
        {view === 'dashboard' && <DashboardView finishers={finishers} setView={setView} setSelectedFinisher={setSelectedFinisher} onExport={handleExportData} />}
        {view === 'editor' && (
          <EditorView 
            selectedFinisher={selectedFinisher} setSelectedFinisher={setSelectedFinisher} 
            style={style} setStyle={setStyle} badgeTheme={badgeTheme} setBadgeTheme={setBadgeTheme}
            isGenerating={isGenerating} handleGenerateAI={handleGenerateAI}
            handleLogoUpload={onFileUpload(logoInputRef, 'logoUrl')}
            handleThemeImageUpload={onFileUpload(themeInputRef, 'themeImageUrl')}
            handleRunnerImageUpload={onFileUpload(runnerInputRef, 'runnerImageUrl')}
            logoInputRef={logoInputRef} themeInputRef={themeInputRef} runnerInputRef={runnerInputRef}
            setView={setView} onSave={handleSave} certificateRef={certificateRef}
          />
        )}
        {view === 'preview' && (
          <div className="min-h-screen bg-slate-900 p-4 sm:p-12 flex flex-col items-center">
             <div className="w-full max-w-5xl flex justify-between mb-10 no-print gap-4">
                <button onClick={() => setView('editor')} className="bg-white/10 text-white border border-white/20 px-8 py-3 rounded-[16px] font-black text-sm active:scale-95 transition-all">返回修改</button>
                <div className="flex gap-3">
                   <button onClick={() => window.print()} className="bg-indigo-600 text-white px-10 py-3 rounded-[16px] font-black text-sm shadow-2xl active:scale-95 transition-all">生成并打印</button>
                </div>
             </div>
             <div className="bg-white p-1 rounded-[16px] shadow-2xl scale-[0.55] sm:scale-[0.8] md:scale-100 origin-top">
                <Certificate data={selectedFinisher} style={style} innerRef={previewCertificateRef} />
             </div>
          </div>
        )}
      </main>
      {view !== 'preview' && (
        <footer className="py-12 bg-white border-t border-slate-100 text-center">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] mb-2">Professional Marathon Solution</p>
          <div className="w-10 h-1 bg-indigo-50 mx-auto"></div>
        </footer>
      )}
    </div>
  );
};

export default App;

