              className="w-full bg-slate-50 border-2 border-slate-100 rounded-[18px] px-6 py-4 text-sm font-bold focus:border-indigo-600 focus:bg-white outline-none transition-all"
              placeholder="请输入安全密码"
            />
          </div>
          {error && <div className="bg-red-50 text-red-500 text-xs font-black py-3 px-4 rounded-xl text-center border border-red-100">{error}</div>}
          <button 
            type="submit"
            className="w-full py-5 bg-indigo-600 text-white rounded-[20px] font-black shadow-2xl shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.98] transition-all text-base"
          >
            安全登录
          </button>
        </form>
      </div>
    </div>
  );
};

