const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [view, setView] = useState<AppView>('home');
  // 初始化时优先读取本地缓存，如果没有则读取代码库的 INITIAL_DATA
  const [finishers, setFinishers] = useState<FinisherData[]>(() => {
    const saved = localStorage.getItem('runcertify_records');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(finishers[0]);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('专业金牌');
  const [searchError, setSearchError] = useState<string | null>(null);

  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);
  const runnerInputRef = useRef<HTMLInputElement>(null);
  const certificateRef = useRef<HTMLDivElement>(null);
  const previewCertificateRef = useRef<HTMLDivElement>(null);

  // 每次修改成绩都会同步到 localStorage (本地有效)
  useEffect(() => {
    localStorage.setItem('runcertify_records', JSON.stringify(finishers));
  }, [finishers]);

  const handleExportData = () => {
    const dataStr = JSON.stringify(finishers, null, 2);
    const codeSnippet = `const INITIAL_DATA: FinisherData[] = ${dataStr};`;
    const blob = new Blob([codeSnippet], { type: 'text/javascript' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'new_initial_data.js';
    link.click();
    alert("【存档包已导出】\n\n请将该文件的内容粘贴至代码库中 App.tsx 的 INITIAL_DATA 数组位置，然后重新部署。这样所有人登录后都能看到这些最新数据！");
  };

  const handleSearch = (name: string) => {
    setSearchError(null);
    if (!name.trim()) {
      setSearchError('请输入姓名进行查询');
      return;
    }
    const found = finishers.find(f => f.name === name.trim());
    if (found) {
      setSelectedFinisher(found);
      setView('search_result');
    } else {
      setSearchError('未找到相关选手的参赛记录，请确保姓名无误。');
    }
  };

  const handleDownload = async () => {
    const ref = (view === 'editor' || view === 'search_result') ? certificateRef : previewCertificateRef;
    if (!ref.current) return;

    setIsDownloading(true);
    try {
      const dataUrl = await htmlToImage.toPng(ref.current, { 
        quality: 1.0, 
        pixelRatio: 2,
        filter: (node: HTMLElement) => {
          if (node.tagName === 'LINK' && (node as HTMLLinkElement).rel === 'stylesheet') return false;
          return true;
        }
      });
      const link = document.createElement('a');
      link.download = `${selectedFinisher.name}_Finish_Certificate.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Download failed', err);
      alert('证书生成失败，请重试。');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const quote = await generateInspirationalQuote(selectedFinisher.name, selectedFinisher.category, selectedFinisher.finishTime, style.language);
      const badge = await generateCustomBadge(badgeTheme);
      setSelectedFinisher(prev => ({ ...prev, inspirationalQuote: quote, badgeImageUrl: badge || prev.badgeImageUrl }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const onFileUpload = (ref: React.RefObject<HTMLInputElement | null>, field: keyof FinisherData) => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, [field]: reader.result as string }));
        if (ref.current) ref.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveToLocal = () => {
    setFinishers(prev => {
      const idx = prev.findIndex(f => f.id === selectedFinisher.id);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = selectedFinisher;
        return next;
      }
      return [selectedFinisher, ...prev];
    });
    setView('dashboard');
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-100 bg-slate-50/30">
      {/* 增强导航：点击 Logo 始终可以回到官网首页 */}
      {(view !== 'home' && view !== 'login') && (
        <Header 
          currentView={view} 
          setView={setView} 
          onLogout={() => { setIsAdmin(false); setView('home'); }} 
        />
      )}

      <main className="flex-1">
        {view === 'home' && (
          <HomeView 
            onSearch={handleSearch} 
            goToLogin={() => { setSearchError(null); setView('login'); }} 
            searchError={searchError}
          />
        )}

        {view === 'login' && (
          <LoginView 
            onLogin={() => { setIsAdmin(true); setView('dashboard'); }} 
            onBack={() => setView('home')} 
          />
        )}

        {view === 'search_result' && (
          <div className="min-h-screen flex flex-col items-center bg-white p-6 sm:p-12 animate-in fade-in duration-700">
            <div className="w-full max-w-5xl flex flex-col sm:flex-row justify-between items-center mb-12 gap-8">
              <div className="text-center sm:text-left">
                <h1 className="text-4xl font-black text-slate-900 tracking-tight">恭喜完赛！</h1>
                <p className="text-slate-400 font-black uppercase tracking-[0.2em] text-[10px] mt-2">OFFICIAL FINISHER VERIFIED - {selectedFinisher.name}</p>
              </div>
              <div className="flex gap-4 w-full sm:w-auto">
                <button onClick={() => setView('home')} className="flex-1 sm:flex-none border-2 border-slate-100 px-8 py-4 rounded-2xl font-black text-slate-400 hover:text-slate-900 transition-all text-sm">
                  回查询页
                </button>
                <button 
                  disabled={isDownloading}
                  onClick={handleDownload}
                  className="flex-1 sm:flex-none bg-indigo-600 text-white px-10 py-4 rounded-[20px] font-black hover:bg-indigo-700 shadow-2xl shadow-indigo-200 transition-all disabled:opacity-50 text-sm active:scale-95"
                >
                  {isDownloading ? '生成中...' : '下载高清电子证书'}
                </button>
              </div>
            </div>

            <div className="certificate-display-wrapper shadow-3xl rounded-[32px] overflow-hidden border border-slate-100 p-2 sm:p-4 bg-slate-50">
               <div className="scale-[0.45] sm:scale-[0.8] md:scale-100 origin-top">
                  <Certificate data={selectedFinisher} style={style} innerRef={certificateRef} />
               </div>
            </div>
          </div>
        )}

        {isAdmin && view === 'dashboard' && (
          <DashboardView 
            finishers={finishers} 
            setView={setView} 
            setSelectedFinisher={setSelectedFinisher} 
            onExport={handleExportData}
          />
        )}

        {isAdmin && view === 'editor' && (
          <div className="max-w-7xl mx-auto px-4 py-8 flex flex-col lg:flex-row gap-10 animate-in fade-in duration-500">
            {/* 编辑器侧边栏优化 */}
            <div className="w-full lg:w-[420px] shrink-0 space-y-6">
              <div className="bg-white p-8 rounded-[32px] shadow-2xl shadow-slate-200 border border-slate-100">
                <h2 className="text-2xl font-black mb-6 text-slate-900 tracking-tight">选手信息编辑</h2>
                <div className="space-y-4">
                   <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase block mb-1.5 px-1 tracking-widest">姓名</label>
                        <input type="text" value={selectedFinisher.name} onChange={e => setSelectedFinisher({...selectedFinisher, name: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 text-sm font-bold focus:border-indigo-600 outline-none" />
                      </div>
                      <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase block mb-1.5 px-1 tracking-widest">参赛号</label>
                        <input type="text" value={selectedFinisher.bibNumber} onChange={e => setSelectedFinisher({...selectedFinisher, bibNumber: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 text-sm font-bold focus:border-indigo-600 outline-none" />
                      </div>
                   </div>
                   <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase block mb-1.5 px-1 tracking-widest">赛事名称</label>
                      <input type="text" value={selectedFinisher.raceName} onChange={e => setSelectedFinisher({...selectedFinisher, raceName: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 text-sm font-bold focus:border-indigo-600 outline-none" />
                   </div>
                   <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase block mb-1.5 px-1 tracking-widest">成绩</label>
                        <input type="text" value={selectedFinisher.finishTime} onChange={e => setSelectedFinisher({...selectedFinisher, finishTime: e.target.value, netTime: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 text-sm font-bold focus:border-indigo-600 outline-none" />
                      </div>
                      <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase block mb-1.5 px-1 tracking-widest">总排名</label>
                        <input type="text" value={selectedFinisher.overallRank} onChange={e => setSelectedFinisher({...selectedFinisher, overallRank: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 py-3 text-sm font-bold focus:border-indigo-600 outline-none" />
                      </div>
                   </div>

                   <div className="pt-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase block mb-3 px-1 tracking-widest">图像管理</label>
                      <div className="grid grid-cols-3 gap-3">
                         <button onClick={() => logoInputRef.current?.click()} className="bg-slate-50 hover:bg-indigo-50 border-2 border-slate-100 rounded-2xl py-3 flex flex-col items-center gap-1 transition-all">
                            <span className="text-[9px] font-black text-slate-500">LOGO</span>
                         </button>
                         <button onClick={() => themeInputRef.current?.click()} className="bg-slate-50 hover:bg-orange-50 border-2 border-slate-100 rounded-2xl py-3 flex flex-col items-center gap-1 transition-all">
                            <span className="text-[9px] font-black text-slate-500">主题</span>
                         </button>
                         <button onClick={() => runnerInputRef.current?.click()} className="bg-slate-50 hover:bg-emerald-50 border-2 border-slate-100 rounded-2xl py-3 flex flex-col items-center gap-1 transition-all">
                            <span className="text-[9px] font-black text-slate-500">照片</span>
                         </button>
                         <input ref={logoInputRef} type="file" accept="image/*" onChange={onFileUpload(logoInputRef, 'logoUrl')} className="hidden" />
                         <input ref={themeInputRef} type="file" accept="image/*" onChange={onFileUpload(themeInputRef, 'themeImageUrl')} className="hidden" />
                         <input ref={runnerInputRef} type="file" accept="image/*" onChange={onFileUpload(runnerInputRef, 'runnerImageUrl')} className="hidden" />
                      </div>
                   </div>
                </div>
              </div>

              <div className="bg-indigo-600 p-8 rounded-[32px] shadow-2xl shadow-indigo-200 text-white">
                <h2 className="text-xl font-black mb-4 flex items-center gap-2 italic">AI Smart Engine</h2>
                <div className="space-y-4">
                  <input type="text" value={badgeTheme} onChange={e => setBadgeTheme(e.target.value)} placeholder="描述勋章风格 (如: 金属拉丝)" className="w-full bg-white/10 border border-white/20 rounded-2xl px-4 py-3 text-sm font-bold outline-none text-white placeholder:text-white/40" />
                  <button disabled={isGenerating || !selectedFinisher.name} onClick={handleGenerateAI} className={`w-full py-4 rounded-2xl font-black text-sm transition-all ${isGenerating ? 'bg-white/20 text-white/50' : 'bg-white text-indigo-700 hover:shadow-xl active:scale-95'}`}>
                    {isGenerating ? 'AI 生成中...' : '生成名言 & 勋章'}
                  </button>
                </div>
              </div>

              <div className="bg-white p-8 rounded-[32px] shadow-2xl shadow-slate-200 border border-slate-100">
                 <h2 className="text-xl font-black mb-6">证书视觉配置</h2>
                 <div className="space-y-4">
                    <div className="grid grid-cols-2 gap-2">
                       <button onClick={() => setStyle({...style, language: 'zh'})} className={`py-3 rounded-2xl text-xs font-black border-2 transition-all ${style.language === 'zh' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>中文版</button>
                       <button onClick={() => setStyle({...style, language: 'en'})} className={`py-3 rounded-2xl text-xs font-black border-2 transition-all ${style.language === 'en' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>English</button>
                    </div>
                    <div className="grid grid-cols-3 gap-2">
                       {['classic', 'modern', 'energetic'].map(t => (
                         <button key={t} onClick={() => setStyle({...style, template: t as any})} className={`py-3 rounded-xl border-2 text-[10px] font-black capitalize transition-all ${style.template === t ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>{t}</button>
