            <div className="w-full max-w-5xl flex justify-between mb-10 no-print gap-4">
               <button onClick={() => setView('editor')} className="bg-white/10 text-white border border-white/20 px-8 py-3 rounded-[16px] font-black text-sm active:scale-95 transition-all">返回编辑</button>
