const App: React.FC = () => {
  const [isAdmin, setIsAdmin] = useState(false);
  const [view, setView] = useState<AppView>('home');
  const [finishers, setFinishers] = useState<FinisherData[]>(() => {
    const saved = localStorage.getItem('runcertify_records');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(finishers[0]);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('专业金质勋章');
  const [searchError, setSearchError] = useState<string | null>(null);

  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);
  const runnerInputRef = useRef<HTMLInputElement>(null);
  const certificateRef = useRef<HTMLDivElement>(null);
  const previewCertificateRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem('runcertify_records', JSON.stringify(finishers));
  }, [finishers]);

  const handleExportData = () => {
    const dataStr = JSON.stringify(finishers, null, 2);
    const codeSnippet = `const INITIAL_DATA: FinisherData[] = ${dataStr};`;
    const blob = new Blob([codeSnippet], { type: 'text/javascript' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'new_initial_data.js';
    link.click();
    alert("【代码库存档包已导出】\n\n请将此文件中的 JSON 数组粘贴回 App.tsx 的 INITIAL_DATA 处，并重新发布代码。这样无论谁登录，都会看到最新的成绩数据。");
  };

  const handleSearch = (name: string) => {
    setSearchError(null);
    if (!name.trim()) {
      setSearchError('请输入姓名进行查询');
      return;
    }
    const found = finishers.find(f => f.name === name.trim());
    if (found) {
      setSelectedFinisher(found);
      setView('search_result');
    } else {
      setSearchError('未找到相关记录，请确保姓名输入准确。');
    }
  };

  const handleDownload = async () => {
    const ref = (view === 'editor' || view === 'search_result') ? certificateRef : previewCertificateRef;
    if (!ref.current) return;

    setIsDownloading(true);
    try {
      const dataUrl = await htmlToImage.toPng(ref.current, { 
        quality: 1.0, 
        pixelRatio: 2,
        cacheBust: true,
      });
      const link = document.createElement('a');
      link.download = `${selectedFinisher.name}_${selectedFinisher.raceName}_证书.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Download failed', err);
      alert('证书下载失败，请尝试在预览页进行。');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const quote = await generateInspirationalQuote(selectedFinisher.name, selectedFinisher.category, selectedFinisher.finishTime, style.language);
      const badge = await generateCustomBadge(badgeTheme);
      setSelectedFinisher(prev => ({ ...prev, inspirationalQuote: quote, badgeImageUrl: badge || prev.badgeImageUrl }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const onFileUpload = (ref: React.RefObject<HTMLInputElement | null>, field: keyof FinisherData) => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, [field]: reader.result as string }));
        if (ref.current) ref.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveToLocal = () => {
    setFinishers(prev => {
      const idx = prev.findIndex(f => f.id === selectedFinisher.id);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = selectedFinisher;
        return next;
      }
      return [selectedFinisher, ...prev];
    });
    setView('dashboard');
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-100 bg-slate-50/20">
      {/* 增强导航 */}
      {(view !== 'home' && view !== 'login') && (
        <Header 
          currentView={view} 
          setView={setView} 
          onLogout={() => { setIsAdmin(false); setView('home'); }} 
        />
      )}

      <main className="flex-1">
        {view === 'home' && (
          <HomeView 
            onSearch={handleSearch} 
            goToLogin={() => { setSearchError(null); setView('login'); }} 
            searchError={searchError}
          />
        )}

        {view === 'login' && (
          <LoginView 
            onLogin={() => { setIsAdmin(true); setView('dashboard'); }} 
            onBack={() => setView('home')} 
          />
        )}

        {view === 'search_result' && (
          <div className="min-h-screen flex flex-col items-center bg-white p-6 sm:p-16 animate-in fade-in duration-700">
            <div className="w-full max-w-5xl flex flex-col sm:flex-row justify-between items-center mb-16 gap-10">
              <div className="text-center sm:text-left">
                <h1 className="text-5xl font-black text-slate-900 tracking-tight leading-none mb-4">荣耀加冕！</h1>
                <p className="text-slate-400 font-black uppercase tracking-[0.3em] text-[12px]">VERIFIED FINISHER - {selectedFinisher.name}</p>
              </div>
              <div className="flex gap-4 w-full sm:w-auto">
                <button onClick={() => setView('home')} className="flex-1 sm:flex-none border-2 border-slate-100 px-10 py-5 rounded-[24px] font-black text-slate-400 hover:text-slate-900 transition-all text-sm">
                  回查询首页
                </button>
                <button 
                  disabled={isDownloading}
                  onClick={handleDownload}
