                  <button disabled={isGenerating || !selectedFinisher.name} onClick={handleGenerateAI} className={`w-full py-5 rounded-2xl font-black text-sm transition-all ${isGenerating ? 'bg-white/20 text-white/50 cursor-wait' : 'bg-white text-indigo-700 hover:shadow-xl active:scale-95'}`}>
                    {isGenerating ? 'AI 正在分析中...' : '智能生成名言 & 勋章'}
