                </div>
              </div>

              <div className="bg-white p-8 sm:p-10 rounded-[40px] shadow-2xl shadow-slate-200 border border-slate-100">
                 <h2 className="text-xl font-black mb-8">证书视觉配置</h2>
                 <div className="space-y-6">
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase block mb-3 px-1 tracking-widest">证书语言</label>
