                         <button onClick={() => setStyle({...style, language: 'en'})} className={`py-3.5 rounded-2xl text-xs font-black border-2 transition-all ${style.language === 'en' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>English</button>
                      </div>
                    </div>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase block mb-3 px-1 tracking-widest">版式方向</label>
                      <div className="grid grid-cols-2 gap-2">
                         <button onClick={() => setStyle({...style, orientation: 'landscape'})} className={`py-3.5 rounded-2xl text-xs font-black border-2 transition-all ${style.orientation === 'landscape' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>横版</button>
                         <button onClick={() => setStyle({...style, orientation: 'portrait'})} className={`py-3.5 rounded-2xl text-xs font-black border-2 transition-all ${style.orientation === 'portrait' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>竖版</button>
                      </div>
                    </div>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase block mb-3 px-1 tracking-widest">设计风格模板</label>
                      <div className="grid grid-cols-2 gap-2">
                         {['classic', 'modern', 'minimal', 'energetic'].map(t => (
                           <button key={t} onClick={() => setStyle({...style, template: t as any})} className={`py-3.5 rounded-2xl border-2 text-[11px] font-black capitalize transition-all ${style.template === t ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 text-slate-400'}`}>{t}</button>
                         ))}
                      </div>
                    </div>
                 </div>
              </div>
            </div>

            <div className="flex-1 flex flex-col items-center">
              <div className="w-full bg-white p-6 sm:p-14 rounded-[56px] shadow-2xl border border-slate-100 flex items-center justify-center overflow-hidden min-h-[500px]">
                <div className="certificate-preview-container origin-center transform scale-[0.4] sm:scale-[0.6] md:scale-85 lg:scale-100 transition-all duration-500">
                  <Certificate data={selectedFinisher} style={style} innerRef={certificateRef} />
                </div>
              </div>
              <div className="mt-12 flex flex-col sm:flex-row gap-5 w-full sm:w-auto mb-16">
                <button onClick={() => setView('preview')} className="w-full sm:px-16 py-5 bg-slate-900 text-white font-black rounded-[24px] shadow-xl hover:bg-slate-800 transition-all text-sm active:scale-95">进入沉浸式预览</button>
                <button onClick={handleSaveToLocal} className="w-full sm:px-16 py-5 bg-indigo-600 text-white font-black rounded-[24px] shadow-xl hover:bg-indigo-700 transition-all text-sm active:scale-95">保存当前选手信息</button>
              </div>
            </div>
          </div>
        )}

        {isAdmin && view === 'preview' && (
          <div className="min-h-screen bg-slate-900 p-6 sm:p-16 flex flex-col items-center">
            <div className="w-full max-w-5xl flex justify-between mb-12 no-print gap-6">
               <button onClick={() => setView('editor')} className="bg-white/10 text-white border border-white/20 px-10 py-4 rounded-[20px] font-black text-sm active:scale-95 transition-all">返回继续编辑</button>
               <div className="flex gap-4">
                  <button onClick={() => window.print()} className="bg-indigo-600 text-white px-12 py-4 rounded-[20px] font-black text-sm shadow-2xl active:scale-95 transition-all">打印此证书</button>
               </div>
            </div>
            <div className="bg-white p-2 rounded-[24px] shadow-3xl scale-[0.5] sm:scale-[0.85] md:scale-100 origin-top">
               <Certificate data={selectedFinisher} style={style} innerRef={previewCertificateRef} />
            </div>
          </div>
        )}
      </main>

      {(view === 'home' || view === 'search_result' || isAdmin) && (
        <footer className="bg-white border-t border-slate-100 py-16 no-print text-center">
          <p className="text-slate-400 text-[10px] sm:text-xs font-black uppercase tracking-[0.4em] mb-4">RunCertify Professional Marathon Infrastructure</p>
          <div className="w-16 h-1.5 bg-indigo-50 mx-auto rounded-full"></div>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import * as htmlToImage from 'html-to-image';
import Header from './components/Header';
import Certificate from './components/Certificate';
import { AppView, FinisherData, CertificateStyle } from './types';
import { generateInspirationalQuote, generateCustomBadge } from './geminiService';

/**
 * 【核心数据存档区】
 * 部署提示：任何人访问官网都能看到此处的数据。
 * 管理员在后台修改成绩后，点击“导出代码快照”，将生成的代码粘贴至此处即可实现永久存档。
 */
const INITIAL_DATA: FinisherData[] = [
  {
    id: '1',
    name: '张杰瑞',
    bibNumber: 'A2045',
    raceName: '2024 城市马拉松',
    category: '全程马拉松 (42.195km)',
    finishTime: '03:45:21',
    netTime: '03:45:21',
    genderRank: '142 / 1200',
    overallRank: '312 / 4500',
    date: '2024年10月24日',
    inspirationalQuote: '奔跑是不设限的自由，脚步丈量的是勇气的疆域。',
  },
  {
    id: '2',
    name: '李安娜',
    bibNumber: 'B1088',
    raceName: '2024 城市马拉松',
    category: '半程马拉松 (21.0975km)',
    finishTime: '01:52:10',
    netTime: '01:51:45',
    genderRank: '85 / 800',
    overallRank: '520 / 3000',
    date: '2024年10月24日',
    inspirationalQuote: '每一次起跑，都是对平凡生活的一次超越。',
  }
];

const INITIAL_STYLE: CertificateStyle = {
  template: 'modern',
  primaryColor: '#4f46e5',
  secondaryColor: '#f59e0b',
  language: 'zh',
  orientation: 'landscape'
};

const App: React.FC = () => {
  // 状态管理
  const [isAdmin, setIsAdmin] = useState(false);
  const [view, setView] = useState<AppView>('home');
  const [finishers, setFinishers] = useState<FinisherData[]>(() => {
    const saved = localStorage.getItem('runcertify_records');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(finishers[0] || INITIAL_DATA[0]);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('金质立体勋章');
  const [searchError, setSearchError] = useState<string | null>(null);
  const [searchName, setSearchName] = useState('');

  // Refs
  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);
  const runnerInputRef = useRef<HTMLInputElement>(null);
  const certificateRef = useRef<HTMLDivElement>(null);

  // 自动同步到本地缓存
  useEffect(() => {
    localStorage.setItem('runcertify_records', JSON.stringify(finishers));
  }, [finishers]);

  // --- 核心业务逻辑 ---

  const handleSearch = () => {
    setSearchError(null);
    if (!searchName.trim()) {
      setSearchError('请输入姓名');
      return;
    }
    const found = finishers.find(f => f.name === searchName.trim());
    if (found) {
      setSelectedFinisher(found);
      setView('search_result');
    } else {
      setSearchError('未找到相关记录，请核实姓名。');
    }
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(finishers, null, 2);
    const codeSnippet = `const INITIAL_DATA: FinisherData[] = ${dataStr};`;
    const blob = new Blob([codeSnippet], { type: 'text/javascript' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'database_snapshot.js';
    link.click();
    alert("【代码库存档包已生成】\n\n请将此文件中的代码覆盖回 App.tsx 的 INITIAL_DATA 处并重新部署。");
  };

  const handleDownload = async () => {
    if (!certificateRef.current) return;
    setIsDownloading(true);
    try {
      const dataUrl = await htmlToImage.toPng(certificateRef.current, { pixelRatio: 2, cacheBust: true });
      const link = document.createElement('a');
      link.download = `证书_${selectedFinisher.name}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      alert('下载失败，请尝试在预览模式下手动截屏或稍后重试。');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const [quote, badge] = await Promise.all([
        generateInspirationalQuote(selectedFinisher.name, selectedFinisher.category, selectedFinisher.finishTime, style.language),
        generateCustomBadge(badgeTheme)
      ]);
      setSelectedFinisher(prev => ({ ...prev, inspirationalQuote: quote, badgeImageUrl: badge || prev.badgeImageUrl }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const onFileUpload = (ref: React.RefObject<HTMLInputElement | null>, field: keyof FinisherData) => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, [field]: reader.result as string }));
        if (ref.current) ref.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveAndBack = () => {
    setFinishers(prev => {
      const idx = prev.findIndex(f => f.id === selectedFinisher.id);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = selectedFinisher;
        return next;
      }
      return [selectedFinisher, ...prev];
    });
    setView('dashboard');
  };

  // --- 视图组件渲染 ---

  const renderMainContent = () => {
    switch (view) {
      case 'home':
        return (
          <div className="min-h-[85vh] flex flex-col items-center justify-center text-center px-6 bg-slate-900 relative overflow-hidden">
            <img src="https://images.unsplash.com/photo-1530541930197-ff16ac917b0e?auto=format&fit=crop&q=80&w=2000" className="absolute inset-0 w-full h-full object-cover opacity-30" />
            <div className="relative z-10 w-full max-w-2xl">
              <h1 className="text-5xl sm:text-7xl font-black text-white mb-8 tracking-tighter">RunCertify<br/><span className="text-indigo-400">成绩查询系统</span></h1>
              <div className="flex flex-col sm:flex-row gap-4 bg-white/10 p-3 rounded-[32px] backdrop-blur-xl border border-white/20">
                <input 
                  type="text" 
                  placeholder="输入参赛姓名" 
                  value={searchName}
                  onChange={(e) => setSearchName(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                  className="flex-1 bg-transparent px-6 py-4 text-white font-bold outline-none text-xl"
                />
                <button onClick={handleSearch} className="bg-indigo-600 hover:bg-indigo-500 text-white font-black px-12 py-4 rounded-[24px] transition-all">查询成绩</button>
              </div>
              {searchError && <p className="mt-4 text-red-400 font-bold">{searchError}</p>}
            </div>
            <button onClick={() => setView('login')} className="absolute bottom-10 text-white/40 hover:text-white font-black text-xs tracking-widest uppercase">管理入口</button>
          </div>
        );

      case 'login':
        return (
          <div className="min-h-screen flex items-center justify-center bg-slate-900 px-6">
            <div className="w-full max-w-md bg-white rounded-[40px] p-10 shadow-3xl">
              <h2 className="text-3xl font-black text-slate-900 text-center mb-8">管理员登录</h2>
              <form className="space-y-6" onSubmit={(e) => {
                e.preventDefault();
                const formData = new FormData(e.currentTarget);
                if (formData.get('account') === '13866668888' && formData.get('password') === '123456') {
                  setIsAdmin(true); setView('dashboard');
                } else {
                  alert('账号或密码不正确');
                }
              }}>
                <input name="account" type="text" placeholder="管理账号" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 font-bold outline-none focus:border-indigo-600" />
                <input name="password" type="password" placeholder="密码" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 font-bold outline-none focus:border-indigo-600" />
                <button type="submit" className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100">登录系统</button>
                <button type="button" onClick={() => setView('home')} className="w-full text-slate-400 font-bold text-sm">返回首页</button>
              </form>
            </div>
          </div>
        );

      case 'dashboard':
        if (!isAdmin) { setView('login'); return null; }
        return (
          <div className="max-w-7xl mx-auto px-6 py-12">
            <div className="flex flex-col md:flex-row justify-between items-end mb-12 gap-6">
              <div>
                <h1 className="text-4xl font-black text-slate-900 tracking-tighter">选手成绩库</h1>
                <p className="text-slate-500 font-medium">修改完成后请点击导出并更新代码库以实现永久发布。</p>
              </div>
              <div className="flex gap-4">
                <button onClick={handleExportData} className="border-2 border-slate-200 px-8 py-4 rounded-2xl font-bold hover:bg-slate-50 transition-all flex items-center gap-2">
                  <svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3"/></svg>
                  导出代码存档
                </button>
                <button onClick={() => {
                  setSelectedFinisher({...INITIAL_DATA[0], id: Math.random().toString(36).substr(2, 9), name: ''});
                  setView('editor');
                }} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-indigo-100">新增选手成绩</button>
              </div>
            </div>
            <div className="bg-white rounded-[40px] shadow-2xl border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-100">
                  <tr>
                    <th className="px-10 py-6 text-xs font-black text-slate-400 uppercase tracking-widest">选手信息</th>
                    <th className="px-10 py-6 text-xs font-black text-slate-400 uppercase tracking-widest">参赛号</th>
                    <th className="px-10 py-6 text-xs font-black text-slate-400 uppercase tracking-widest">成绩</th>
                    <th className="px-10 py-6 text-xs font-black text-slate-400 uppercase tracking-widest text-right">管理</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {finishers.map(f => (
                    <tr key={f.id} className="hover:bg-slate-50 transition-all">
                      <td className="px-10 py-7">
                        <div className="font-black text-slate-800 text-lg">{f.name || '未命名'}</div>
                        <div className="text-xs text-slate-400 font-bold">{f.raceName}</div>
                      </td>
                      <td className="px-10 py-7"><span className="bg-indigo-50 text-indigo-600 px-3 py-1 rounded-lg font-mono font-black">{f.bibNumber}</span></td>
                      <td className="px-10 py-7 font-black text-slate-900">{f.finishTime}</td>
                      <td className="px-10 py-7 text-right">
                        <button onClick={() => { setSelectedFinisher(f); setView('editor'); }} className="text-indigo-600 font-black text-xs uppercase tracking-widest hover:underline">编辑/配置</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );

      case 'editor':
        if (!isAdmin) { setView('login'); return null; }
        return (
          <div className="max-w-7xl mx-auto px-6 py-10 flex flex-col lg:flex-row gap-12">
