                <div className="grid grid-cols-2 gap-4">
                  <input type="text" value={selectedFinisher.bibNumber} onChange={e => setSelectedFinisher({...selectedFinisher, bibNumber: e.target.value})} placeholder="号码布" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 font-bold outline-none focus:border-indigo-600" />
                  <input type="text" value={selectedFinisher.finishTime} onChange={e => setSelectedFinisher({...selectedFinisher, finishTime: e.target.value, netTime: e.target.value})} placeholder="成绩" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 font-bold outline-none focus:border-indigo-600" />
                </div>
              </div>

              <div className="bg-indigo-600 p-8 rounded-[40px] text-white space-y-4">
                <h3 className="font-black italic">Gemini AI 智能加持</h3>
                <input type="text" value={badgeTheme} onChange={e => setBadgeTheme(e.target.value)} placeholder="描述勋章风格..." className="w-full bg-white/10 border border-white/20 rounded-2xl px-5 py-4 text-sm font-bold outline-none placeholder:text-white/40" />
                <button disabled={isGenerating || !selectedFinisher.name} onClick={handleGenerateAI} className={`w-full py-4 rounded-2xl font-black text-sm transition-all ${isGenerating ? 'bg-white/20' : 'bg-white text-indigo-700 active:scale-95'}`}>
                  {isGenerating ? 'AI 解析中...' : '生成名言 & 勋章'}
