                  <div className="flex gap-2">
                    <button onClick={() => setStyle({...style, orientation: 'landscape'})} className={`flex-1 py-3 rounded-xl font-black text-xs border-2 ${style.orientation === 'landscape' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-100 text-slate-400'}`}>横版</button>
                    <button onClick={() => setStyle({...style, orientation: 'portrait'})} className={`flex-1 py-3 rounded-xl font-black text-xs border-2 ${style.orientation === 'portrait' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-100 text-slate-400'}`}>竖版</button>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    {['classic', 'modern', 'minimal', 'energetic'].map(t => (
                      <button key={t} onClick={() => setStyle({...style, template: t as any})} className={`py-3 rounded-xl font-black text-xs border-2 capitalize ${style.template === t ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-100 text-slate-400'}`}>{t}</button>
                    ))}
                  </div>
                  <div className="grid grid-cols-3 gap-2">
                    <button onClick={() => logoInputRef.current?.click()} className="py-3 bg-slate-50 rounded-xl text-[10px] font-black uppercase text-slate-500 hover:bg-slate-100">Logo</button>
                    <button onClick={() => themeInputRef.current?.click()} className="py-3 bg-slate-50 rounded-xl text-[10px] font-black uppercase text-slate-500 hover:bg-slate-100">背景</button>
                    <button onClick={() => runnerInputRef.current?.click()} className="py-3 bg-slate-50 rounded-xl text-[10px] font-black uppercase text-slate-500 hover:bg-slate-100">照片</button>
                  </div>
                </div>
              </div>
              <input ref={logoInputRef} type="file" accept="image/*" onChange={onFileUpload(logoInputRef, 'logoUrl')} className="hidden" />
              <input ref={themeInputRef} type="file" accept="image/*" onChange={onFileUpload(themeInputRef, 'themeImageUrl')} className="hidden" />
              <input ref={runnerInputRef} type="file" accept="image/*" onChange={onFileUpload(runnerInputRef, 'runnerImageUrl')} className="hidden" />
            </div>

            <div className="flex-1 flex flex-col items-center">
              <div className="w-full bg-white p-10 rounded-[56px] shadow-3xl border border-slate-100 flex items-center justify-center overflow-hidden">
                <div className="transform scale-[0.45] sm:scale-[0.8] md:scale-95 lg:scale-100 transition-all origin-center">
                  <Certificate data={selectedFinisher} style={style} innerRef={certificateRef} />
                </div>
              </div>
              <div className="mt-12 flex gap-4 w-full justify-center">
                <button onClick={() => setView('preview')} className="px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-xl active:scale-95">全屏预览</button>
                <button onClick={handleSaveAndBack} className="px-12 py-5 bg-indigo-600 text-white font-black rounded-2xl shadow-xl active:scale-95">确认保存修改</button>
              </div>
            </div>
          </div>
        );

      case 'preview':
        return (
          <div className="min-h-screen bg-slate-900 flex flex-col items-center p-10">
            <div className="w-full max-w-5xl flex justify-between mb-12">
              <button onClick={() => setView(isAdmin ? 'editor' : 'search_result')} className="text-white/60 font-black hover:text-white uppercase tracking-widest text-xs">返回修改</button>
              <button onClick={() => window.print()} className="bg-white text-slate-900 px-10 py-4 rounded-2xl font-black">打印证书</button>
            </div>
            <div className="bg-white p-1 rounded-2xl shadow-4xl scale-[0.55] sm:scale-[0.9] md:scale-100 origin-top">
              <Certificate data={selectedFinisher} style={style} />
            </div>
          </div>
        );

      case 'search_result':
        return (
          <div className="min-h-screen bg-white flex flex-col items-center p-8 sm:p-16">
            <div className="w-full max-w-5xl flex flex-col sm:flex-row justify-between items-center mb-16 gap-10">
              <div className="text-center sm:text-left">
                <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tighter italic">VICTORY!</h1>
                <p className="text-slate-400 font-black tracking-widest uppercase text-xs">官方验证完赛选手: {selectedFinisher.name}</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => setView('home')} className="border-2 border-slate-100 px-10 py-5 rounded-[24px] font-black text-slate-400 hover:text-slate-900">回首页</button>
                <button disabled={isDownloading} onClick={handleDownload} className="bg-indigo-600 text-white px-12 py-5 rounded-[24px] font-black shadow-2xl active:scale-95">
                  {isDownloading ? '生成中...' : '下载高清电子证书'}
                </button>
              </div>
            </div>
            <div className="shadow-4xl rounded-[48px] border-8 border-slate-50 p-4 bg-slate-50">
              <div className="scale-[0.45] sm:scale-[0.8] md:scale-95 lg:scale-100 origin-top">
                <Certificate data={selectedFinisher} style={style} innerRef={certificateRef} />
              </div>
            </div>
          </div>
        );

      default:
        setView('home');
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50/20 font-inter">
      {(view !== 'home' && view !== 'login' && view !== 'preview') && (
        <Header currentView={view} setView={setView} onLogout={() => { setIsAdmin(false); setView('home'); }} />
      )}
      <main className="flex-1">
        {renderMainContent()}
      </main>
      {(view === 'home' || isAdmin) && (
        <footer className="bg-white border-t border-slate-100 py-16 text-center no-print">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.4em]">RunCertify Marathon Tech Solutions</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import * as htmlToImage from 'html-to-image';
import Header from './components/Header';
import Certificate from './components/Certificate';
import { AppView, FinisherData, CertificateStyle } from './types';
import { generateInspirationalQuote, generateCustomBadge } from './geminiService';

/**
 * 【核心数据存档区】
 * 部署提示：任何人访问官网都能看到此处的数据。
 * 管理员在后台修改成绩后，点击“导出代码快照”，将生成的代码粘贴至此处即可实现永久存档。
 */
const INITIAL_DATA: FinisherData[] = [
  {
    id: '1',
    name: '张杰瑞',
    bibNumber: 'A2045',
    raceName: '2024 城市马拉松',
    category: '全程马拉松 (42.195km)',
    finishTime: '03:45:21',
    netTime: '03:45:21',
    genderRank: '142 / 1200',
    overallRank: '312 / 4500',
    date: '2024年10月24日',
    inspirationalQuote: '奔跑是不设限的自由，脚步丈量的是勇气的疆域。',
  },
  {
    id: '2',
    name: '李安娜',
    bibNumber: 'B1088',
    raceName: '2024 城市马拉松',
    category: '半程马拉松 (21.0975km)',
    finishTime: '01:52:10',
    netTime: '01:51:45',
    genderRank: '85 / 800',
    overallRank: '520 / 3000',
    date: '2024年10月24日',
    inspirationalQuote: '每一次起跑，都是对平凡生活的一次超越。',
  }
];

const INITIAL_STYLE: CertificateStyle = {
  template: 'modern',
  primaryColor: '#4f46e5',
  secondaryColor: '#f59e0b',
  language: 'zh',
  orientation: 'landscape'
};

const App: React.FC = () => {
  // 状态管理
  const [isAdmin, setIsAdmin] = useState(false);
  const [view, setView] = useState<AppView>('home');
  const [finishers, setFinishers] = useState<FinisherData[]>(() => {
    const saved = localStorage.getItem('runcertify_records');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(finishers[0] || INITIAL_DATA[0]);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('金质立体勋章');
  const [searchError, setSearchError] = useState<string | null>(null);
  const [searchName, setSearchName] = useState('');

  // Refs
  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);
  const runnerInputRef = useRef<HTMLInputElement>(null);
  const certificateRef = useRef<HTMLDivElement>(null);

  // 自动同步到本地缓存
  useEffect(() => {
    localStorage.setItem('runcertify_records', JSON.stringify(finishers));
  }, [finishers]);

  // --- 核心业务逻辑 ---

  const handleSearch = () => {
    setSearchError(null);
    if (!searchName.trim()) {
      setSearchError('请输入姓名');
      return;
    }
    const found = finishers.find(f => f.name === searchName.trim());
    if (found) {
      setSelectedFinisher(found);
      setView('search_result');
    } else {
      setSearchError('未找到相关记录，请核实姓名。');
    }
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(finishers, null, 2);
    const codeSnippet = `const INITIAL_DATA: FinisherData[] = ${dataStr};`;
    const blob = new Blob([codeSnippet], { type: 'text/javascript' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'database_snapshot.js';
    link.click();
    alert("【代码库存档包已生成】\n\n请将此文件中的代码覆盖回 App.tsx 的 INITIAL_DATA 处并重新部署。");
  };

  const handleDownload = async () => {
    if (!certificateRef.current) return;
    setIsDownloading(true);
    try {
      const dataUrl = await htmlToImage.toPng(certificateRef.current, { pixelRatio: 2, cacheBust: true });
      const link = document.createElement('a');
      link.download = `证书_${selectedFinisher.name}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      alert('下载失败，请尝试在预览模式下手动截屏或稍后重试。');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const [quote, badge] = await Promise.all([
        generateInspirationalQuote(selectedFinisher.name, selectedFinisher.category, selectedFinisher.finishTime, style.language),
        generateCustomBadge(badgeTheme)
      ]);
      setSelectedFinisher(prev => ({ ...prev, inspirationalQuote: quote, badgeImageUrl: badge || prev.badgeImageUrl }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const onFileUpload = (ref: React.RefObject<HTMLInputElement | null>, field: keyof FinisherData) => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, [field]: reader.result as string }));
        if (ref.current) ref.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveAndBack = () => {
    setFinishers(prev => {
      const idx = prev.findIndex(f => f.id === selectedFinisher.id);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = selectedFinisher;
        return next;
      }
      return [selectedFinisher, ...prev];
    });
    setView('dashboard');
  };

  const renderMainContent = () => {
    switch (view) {
      case 'home':
        return (
          <div className="min-h-[90vh] flex flex-col items-center justify-center text-center px-6 bg-slate-900 relative overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-br from-indigo-900 via-slate-900 to-black"></div>
            <img src="https://images.unsplash.com/photo-1530541930197-ff16ac917b0e?auto=format&fit=crop&q=80&w=2000" className="absolute inset-0 w-full h-full object-cover opacity-20 mix-blend-overlay" />
            <div className="relative z-10 w-full max-w-4xl">
              <div className="inline-flex items-center gap-2 bg-white/10 px-4 py-2 rounded-full border border-white/20 mb-8 backdrop-blur-md">
                <span className="w-2 h-2 bg-indigo-500 rounded-full animate-pulse"></span>
                <span className="text-white/60 text-[10px] font-black uppercase tracking-widest">Official Verification System</span>
              </div>
              <h1 className="text-6xl sm:text-8xl font-black text-white mb-8 tracking-tighter leading-none">
                RunCertify<br/>
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-emerald-400">完赛成就系统</span>
              </h1>
              <div className="max-w-xl mx-auto flex flex-col sm:flex-row gap-4 bg-white/10 p-2.5 rounded-[32px] backdrop-blur-2xl border border-white/20 shadow-2xl">
                <input 
                  type="text" 
                  placeholder="请输入您的参赛姓名" 
                  value={searchName}
                  onChange={(e) => setSearchName(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                  className="flex-1 bg-transparent px-8 py-4 text-white font-bold outline-none text-xl placeholder:text-white/30"
                />
                <button onClick={handleSearch} className="bg-white text-indigo-950 font-black px-12 py-4 rounded-[24px] hover:bg-indigo-50 transition-all shadow-xl active:scale-95">查询记录</button>
              </div>
              {searchError && <p className="mt-6 text-red-400 font-bold animate-pulse">{searchError}</p>}
            </div>
            <button onClick={() => setView('login')} className="absolute bottom-12 text-white/30 hover:text-white font-black text-[10px] tracking-[0.3em] uppercase transition-colors">Admin Panel Access</button>
          </div>
        );

      case 'login':
        return (
          <div className="min-h-screen flex items-center justify-center bg-slate-950 px-6 relative">
             <div className="absolute inset-0 bg-gradient-to-tr from-indigo-950/20 to-transparent pointer-events-none"></div>
             <div className="w-full max-w-md bg-white rounded-[48px] p-12 shadow-[0_32px_120px_-20px_rgba(0,0,0,0.5)] relative z-10">
              <div className="text-center mb-10">
                <div className="w-16 h-16 bg-indigo-600 rounded-3xl mx-auto mb-6 flex items-center justify-center text-white shadow-2xl shadow-indigo-200">
                  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>
                </div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">后台安全验证</h2>
                <p className="text-slate-400 font-medium mt-1">请输入管理员授信凭据</p>
              </div>
              <form className="space-y-6" onSubmit={(e) => {
                e.preventDefault();
                const formData = new FormData(e.currentTarget);
                if (formData.get('account') === '13866668888' && formData.get('password') === '123456') {
                  setIsAdmin(true); setView('dashboard');
                } else {
                  alert('验证未通过，请核对信息');
                }
              }}>
                <div className="space-y-4">
                  <input name="account" type="text" placeholder="管理账号" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4.5 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                  <input name="password" type="password" placeholder="授权密码" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4.5 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                </div>
                <button type="submit" className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-[0.98]">进入控制台</button>
                <button type="button" onClick={() => setView('home')} className="w-full text-slate-400 font-bold text-xs uppercase tracking-widest hover:text-slate-900 transition-colors">返回门户首页</button>
              </form>
            </div>
          </div>
        );

      case 'dashboard':
        if (!isAdmin) { setView('login'); return null; }
        return (
          <div className="max-w-7xl mx-auto px-6 py-16 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col md:flex-row justify-between items-end mb-16 gap-8">
              <div>
                <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider mb-4">
                  <span className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-pulse"></span>
                  Active Database
