                <button onClick={handleExportData} className="flex-1 md:flex-none border-2 border-slate-200 px-8 py-4.5 rounded-[22px] font-bold hover:bg-slate-50 transition-all flex items-center justify-center gap-3 group">
                  <svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24" className="group-hover:translate-y-0.5 transition-transform"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3"/></svg>
