                    <button onClick={handleSaveAndBack} className="flex-1 px-14 py-5 bg-indigo-600 text-white font-black rounded-3xl shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-[0.98] text-sm tracking-widest uppercase">保存此条数据</button>
                  </div>

                  <p className="mt-10 text-slate-400 font-bold text-xs max-w-md text-center">注意：实时预览可能受屏幕比例影响。下载或打印时将使用官方高分辨率原始尺寸。</p>
                </div>
              </div>
            </div>
          </div>
        );

      case 'preview':
        return (
          <div className="min-h-screen bg-slate-950 flex flex-col items-center p-12">
            <div className="w-full max-w-6xl flex flex-col sm:flex-row justify-between items-center mb-16 no-print gap-8">
