import Header from './components/Header';
import Certificate from './components/Certificate';
import { AppView, FinisherData, CertificateStyle } from './types';
import { generateInspirationalQuote, generateCustomBadge } from './geminiService';

/**
 * 【核心数据存档区】
 * 部署提示：任何人访问官网都能看到此处的数据。
 * 管理员在后台修改成绩后，点击“导出代码快照”，将生成的代码粘贴至此处即可实现永久存档。
 */
const INITIAL_DATA: FinisherData[] = [
  {
    id: '1',
    name: '张杰瑞',
    bibNumber: 'A2045',
    raceName: '2024 城市马拉松',
    category: '全程马拉松 (42.195km)',
    finishTime: '03:45:21',
    netTime: '03:45:21',
    genderRank: '142 / 1200',
    overallRank: '312 / 4500',
    date: '2024年10月24日',
    inspirationalQuote: '奔跑是不设限的自由，脚步丈量的是勇气的疆域。',
  },
  {
    id: '2',
    name: '李安娜',
    bibNumber: 'B1088',
    raceName: '2024 城市马拉松',
    category: '半程马拉松 (21.0975km)',
    finishTime: '01:52:10',
    netTime: '01:51:45',
    genderRank: '85 / 800',
    overallRank: '520 / 3000',
    date: '2024年10月24日',
    inspirationalQuote: '每一次起跑，都是对平凡生活的一次超越。',
  }
];

const INITIAL_STYLE: CertificateStyle = {
  template: 'modern',
  primaryColor: '#4f46e5',
  secondaryColor: '#f59e0b',
  language: 'zh',
  orientation: 'landscape'
};

const App: React.FC = () => {
  // 状态管理
  const [isAdmin, setIsAdmin] = useState(false);
  const [view, setView] = useState<AppView>('home');
  const [finishers, setFinishers] = useState<FinisherData[]>(() => {
    const saved = localStorage.getItem('runcertify_records');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(finishers[0] || INITIAL_DATA[0]);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('金质立体勋章');
  const [searchError, setSearchError] = useState<string | null>(null);
  const [searchName, setSearchName] = useState('');

  // Refs
  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);
  const runnerInputRef = useRef<HTMLInputElement>(null);
  const certificateRef = useRef<HTMLDivElement>(null);

  // 自动同步到本地缓存
  useEffect(() => {
    localStorage.setItem('runcertify_records', JSON.stringify(finishers));
  }, [finishers]);

  // --- 核心业务逻辑 ---

  const handleSearch = () => {
    setSearchError(null);
    if (!searchName.trim()) {
      setSearchError('请输入姓名');
      return;
    }
    const found = finishers.find(f => f.name === searchName.trim());
    if (found) {
      setSelectedFinisher(found);
      setView('search_result');
    } else {
      setSearchError('未找到相关记录，请核实姓名。');
    }
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(finishers, null, 2);
    const codeSnippet = `const INITIAL_DATA: FinisherData[] = ${dataStr};`;
    const blob = new Blob([codeSnippet], { type: 'text/javascript' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'database_snapshot.js';
    link.click();
    alert("【代码库存档包已生成】\n\n请将此文件中的代码覆盖回 App.tsx 的 INITIAL_DATA 处并重新部署。");
  };

  const handleDownload = async () => {
    if (!certificateRef.current) return;
    setIsDownloading(true);
    try {
      const dataUrl = await htmlToImage.toPng(certificateRef.current, { pixelRatio: 2, cacheBust: true });
      const link = document.createElement('a');
      link.download = `证书_${selectedFinisher.name}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      alert('下载失败，请尝试在预览模式下手动截屏或稍后重试。');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const [quote, badge] = await Promise.all([
        generateInspirationalQuote(selectedFinisher.name, selectedFinisher.category, selectedFinisher.finishTime, style.language),
        generateCustomBadge(badgeTheme)
      ]);
      setSelectedFinisher(prev => ({ ...prev, inspirationalQuote: quote, badgeImageUrl: badge || prev.badgeImageUrl }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const onFileUpload = (ref: React.RefObject<HTMLInputElement | null>, field: keyof FinisherData) => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, [field]: reader.result as string }));
        if (ref.current) ref.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveAndBack = () => {
    setFinishers(prev => {
      const idx = prev.findIndex(f => f.id === selectedFinisher.id);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = selectedFinisher;
        return next;
      }
      return [selectedFinisher, ...prev];
    });
    setView('dashboard');
  };

  const renderMainContent = () => {
    switch (view) {
      case 'home':
        return (
          <div className="min-h-[90vh] flex flex-col items-center justify-center text-center px-6 bg-slate-950 relative overflow-hidden">
            <img src="https://images.unsplash.com/photo-1530541930197-ff16ac917b0e?auto=format&fit=crop&q=80&w=2000" className="absolute inset-0 w-full h-full object-cover opacity-10 mix-blend-screen" />
            <div className="relative z-10 w-full max-w-4xl">
              <h1 className="text-6xl sm:text-8xl font-black text-white mb-6 tracking-tighter leading-none">
                RunCertify<br/>
                <span className="text-indigo-500">成就查询系统</span>
              </h1>
              <p className="text-slate-400 mb-12 text-lg font-medium tracking-wide">请输入您的姓名查询官方完赛证书</p>
              <div className="max-w-xl mx-auto flex flex-col sm:flex-row gap-4 bg-white p-2 rounded-[28px] shadow-2xl">
                <input 
                  type="text" 
                  placeholder="选手姓名" 
                  value={searchName}
                  onChange={(e) => setSearchName(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                  className="flex-1 bg-transparent px-8 py-4 text-slate-900 font-bold outline-none text-xl placeholder:text-slate-300"
                />
                <button onClick={handleSearch} className="bg-indigo-600 text-white font-black px-12 py-4 rounded-[22px] hover:bg-indigo-700 transition-all shadow-xl active:scale-95">查询记录</button>
              </div>
              {searchError && <p className="mt-6 text-red-500 font-bold">{searchError}</p>}
            </div>
            <button onClick={() => setView('login')} className="absolute bottom-12 text-slate-600 hover:text-white font-black text-[10px] tracking-widest uppercase transition-colors">Admin Entry</button>
          </div>
        );

      case 'login':
        return (
          <div className="min-h-screen flex items-center justify-center bg-slate-50 px-6">
             <div className="w-full max-w-md bg-white rounded-[40px] p-12 shadow-2xl border border-slate-100">
              <div className="text-center mb-10">
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">管理员验证</h2>
                <p className="text-slate-400 font-medium mt-1">授权访问证书管理后台</p>
              </div>
              <form className="space-y-6" onSubmit={(e) => {
                e.preventDefault();
                const formData = new FormData(e.currentTarget);
                if (formData.get('account') === '13866668888' && formData.get('password') === '123456') {
                  setIsAdmin(true); setView('dashboard');
                } else {
                  alert('验证失败');
                }
              }}>
                <div className="space-y-4">
                  <input name="account" type="text" placeholder="管理账号" className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4.5 font-bold outline-none focus:border-indigo-600 transition-all" />
                  <input name="password" type="password" placeholder="授权密码" className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4.5 font-bold outline-none focus:border-indigo-600 transition-all" />
                </div>
                <button type="submit" className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-lg hover:bg-indigo-700 transition-all">进入系统</button>
                <button type="button" onClick={() => setView('home')} className="w-full text-slate-400 font-bold text-xs uppercase tracking-widest hover:text-slate-900 transition-colors">返回门户首页</button>
              </form>
            </div>
          </div>
        );

      case 'dashboard':
        if (!isAdmin) { setView('login'); return null; }
        return (
          <div className="max-w-7xl mx-auto px-6 py-12">
            <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
              <div>
                <h1 className="text-4xl font-black text-slate-900 tracking-tight">选手成绩库</h1>
                <p className="text-slate-400 font-medium mt-1">目前共有 {finishers.length} 条有效记录</p>
              </div>
              <div className="flex gap-4">
                <button onClick={handleExportData} className="bg-white border-2 border-slate-100 px-6 py-3.5 rounded-2xl font-bold text-slate-600 hover:bg-slate-50 transition-all">
                  导出存档
                </button>
                <button onClick={() => {
                  setSelectedFinisher({...INITIAL_DATA[0], id: Math.random().toString(36).substr(2, 9), name: '', category: ''});
                  setView('editor');
                }} className="bg-indigo-600 text-white px-8 py-3.5 rounded-2xl font-black shadow-indigo-100 hover:bg-indigo-700 transition-all">
                  录入成绩
                </button>
              </div>
            </div>
            <div className="bg-white rounded-[32px] shadow-xl border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-100">
                  <tr>
                    <th className="px-8 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest">选手</th>
                    <th className="px-8 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest">参赛项目</th>
                    <th className="px-8 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest">成绩</th>
                    <th className="px-8 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest">参赛号</th>
                    <th className="px-8 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest text-right">操作</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {finishers.map(f => (
                    <tr key={f.id} className="hover:bg-slate-50/50 transition-all group">
                      <td className="px-8 py-6 font-black text-slate-900 text-lg">{f.name || '-'}</td>
                      <td className="px-8 py-6 text-sm font-bold text-slate-500">{f.category || '-'}</td>
                      <td className="px-8 py-6 font-mono font-black text-indigo-600">{f.finishTime}</td>
                      <td className="px-8 py-6 text-sm font-bold text-slate-400">{f.bibNumber}</td>
                      <td className="px-8 py-6 text-right">
                        <button onClick={() => { setSelectedFinisher(f); setView('editor'); }} className="text-xs font-black text-indigo-600 hover:underline uppercase tracking-widest">编辑证书</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );

      case 'editor':
        if (!isAdmin) { setView('login'); return null; }
        return (
          <div className="min-h-screen bg-slate-50">
            <div className="max-w-[1440px] mx-auto px-6 py-8">
              <div className="flex flex-col lg:flex-row gap-8">
                {/* Left side: Controls */}
                <div className="w-full lg:w-[420px] shrink-0 space-y-6">
                  {/* Info Card */}
                  <div className="bg-white p-8 rounded-[32px] shadow-sm border border-slate-200">
                    <h3 className="text-lg font-black mb-6 flex items-center gap-2">
                      <span className="w-1.5 h-6 bg-indigo-600 rounded-full"></span>
                      选手基本信息
                    </h3>
                    <div className="space-y-4">
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase ml-1">姓名</label>
                          <input type="text" value={selectedFinisher.name} onChange={e => setSelectedFinisher({...selectedFinisher, name: e.target.value})} className="w-full bg-slate-50 rounded-xl px-4 py-3 font-bold text-sm outline-none focus:ring-2 ring-indigo-500/20" />
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase ml-1">参赛号</label>
                          <input type="text" value={selectedFinisher.bibNumber} onChange={e => setSelectedFinisher({...selectedFinisher, bibNumber: e.target.value})} className="w-full bg-slate-50 rounded-xl px-4 py-3 font-bold text-sm outline-none focus:ring-2 ring-indigo-500/20" />
                        </div>
                      </div>
                      <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-1">参赛项目</label>
                        <input type="text" value={selectedFinisher.category} onChange={e => setSelectedFinisher({...selectedFinisher, category: e.target.value})} placeholder="如: 全程马拉松" className="w-full bg-slate-50 rounded-xl px-4 py-3 font-bold text-sm outline-none focus:ring-2 ring-indigo-500/20" />
                      </div>
                      <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-1">赛事全称</label>
                        <input type="text" value={selectedFinisher.raceName} onChange={e => setSelectedFinisher({...selectedFinisher, raceName: e.target.value})} className="w-full bg-slate-50 rounded-xl px-4 py-3 font-bold text-sm outline-none focus:ring-2 ring-indigo-500/20" />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase ml-1">完赛成绩</label>
                          <input type="text" value={selectedFinisher.finishTime} onChange={e => setSelectedFinisher({...selectedFinisher, finishTime: e.target.value, netTime: e.target.value})} className="w-full bg-slate-50 rounded-xl px-4 py-3 font-bold text-sm outline-none focus:ring-2 ring-indigo-500/20" />
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase ml-1">综合排名</label>
                          <input type="text" value={selectedFinisher.overallRank} onChange={e => setSelectedFinisher({...selectedFinisher, overallRank: e.target.value})} className="w-full bg-slate-50 rounded-xl px-4 py-3 font-bold text-sm outline-none focus:ring-2 ring-indigo-500/20" />
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* AI & Visual Card */}
                  <div className="bg-indigo-600 p-8 rounded-[32px] text-white space-y-4">
                    <h3 className="font-black italic text-lg">Gemini AI 增强</h3>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-indigo-200 uppercase ml-1">勋章风格描述</label>
                       <input type="text" value={badgeTheme} onChange={e => setBadgeTheme(e.target.value)} className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-sm font-bold outline-none focus:bg-white/20" />
                    </div>
                    <button disabled={isGenerating || !selectedFinisher.name} onClick={handleGenerateAI} className={`w-full py-4 rounded-xl font-black text-sm transition-all ${isGenerating ? 'bg-white/20 cursor-wait' : 'bg-white text-indigo-700 hover:scale-[1.02] shadow-xl active:scale-95'}`}>
                      {isGenerating ? '正在解析中...' : '一键生成 AI 名言与勋章'}
                    </button>
                  </div>

                  {/* Style Control Card */}
                  <div className="bg-white p-8 rounded-[32px] shadow-sm border border-slate-200 space-y-6">
                    <h3 className="text-lg font-black">证书视觉控制</h3>
                    <div className="space-y-4">
                      <div className="flex gap-2">
                        <button onClick={() => setStyle({...style, orientation: 'landscape'})} className={`flex-1 py-3 rounded-xl font-black text-xs uppercase tracking-widest border-2 transition-all ${style.orientation === 'landscape' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>横版</button>
                        <button onClick={() => setStyle({...style, orientation: 'portrait'})} className={`flex-1 py-3 rounded-xl font-black text-xs uppercase tracking-widest border-2 transition-all ${style.orientation === 'portrait' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>竖版</button>
                      </div>
                      <div className="grid grid-cols-2 gap-2">
                        {['classic', 'modern', 'minimal', 'energetic'].map(t => (
                          <button key={t} onClick={() => setStyle({...style, template: t as any})} className={`py-3 rounded-xl font-black text-[10px] uppercase tracking-widest border-2 transition-all ${style.template === t ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>{t}</button>
                        ))}
                      </div>
                      <div className="grid grid-cols-3 gap-2">
                        <button onClick={() => logoInputRef.current?.click()} className="py-3 bg-slate-50 hover:bg-slate-100 rounded-xl text-[9px] font-black uppercase text-slate-400 transition-colors">Logo</button>
                        <button onClick={() => themeInputRef.current?.click()} className="py-3 bg-slate-50 hover:bg-slate-100 rounded-xl text-[9px] font-black uppercase text-slate-400 transition-colors">背景图</button>
                        <button onClick={() => runnerInputRef.current?.click()} className="py-3 bg-slate-50 hover:bg-slate-100 rounded-xl text-[9px] font-black uppercase text-slate-400 transition-colors">照片</button>
                      </div>
                    </div>
                  </div>

                  <input ref={logoInputRef} type="file" accept="image/*" onChange={onFileUpload(logoInputRef, 'logoUrl')} className="hidden" />
                  <input ref={themeInputRef} type="file" accept="image/*" onChange={onFileUpload(themeInputRef, 'themeImageUrl')} className="hidden" />
                  <input ref={runnerInputRef} type="file" accept="image/*" onChange={onFileUpload(runnerInputRef, 'runnerImageUrl')} className="hidden" />
                </div>

                {/* Right side: Preview */}
                <div className="flex-1 flex flex-col items-center">
                  <div className="w-full bg-white p-12 rounded-[40px] shadow-sm border border-slate-200 flex items-center justify-center min-h-[500px] overflow-hidden">
                    <div className="transform scale-[0.5] sm:scale-[0.8] xl:scale-100 transition-all origin-center drop-shadow-2xl">
                      <Certificate data={selectedFinisher} style={style} innerRef={certificateRef} />
                    </div>
                  </div>
                  <div className="mt-8 flex gap-4 w-full justify-center max-w-lg px-6">
                    <button onClick={() => setView('preview')} className="flex-1 px-8 py-4 border-2 border-slate-900 font-black rounded-2xl transition-all active:scale-95">全屏预览</button>
                    <button onClick={handleSaveAndBack} className="flex-1 px-8 py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">确认保存</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );

      case 'preview':
        return (
          <div className="min-h-screen bg-slate-900 flex flex-col items-center p-8">
            <div className="w-full max-w-5xl flex justify-between mb-8 no-print">
              <button onClick={() => setView(isAdmin ? 'editor' : 'search_result')} className="text-white/40 hover:text-white font-black text-xs uppercase tracking-widest transition-colors">返回</button>
              <button onClick={() => window.print()} className="bg-white text-slate-950 px-8 py-3 rounded-xl font-black">打印证书</button>
            </div>
            <div className="bg-white p-1 rounded-2xl shadow-4xl scale-[0.5] sm:scale-[0.9] md:scale-100 xl:scale-125 origin-top transition-transform">
              <Certificate data={selectedFinisher} style={style} />
            </div>
          </div>
        );

      case 'search_result':
        return (
          <div className="min-h-screen bg-white flex flex-col items-center p-10 sm:p-24">
            <div className="w-full max-w-6xl flex flex-col xl:flex-row justify-between items-center mb-16 gap-12">
              <div className="text-center xl:text-left">
                <h1 className="text-6xl sm:text-8xl font-black text-slate-950 mb-4 tracking-tighter italic">FINISHER!</h1>
                <p className="text-slate-400 font-black tracking-widest uppercase text-xs">官方核验完赛选手: {selectedFinisher.name}</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => setView('home')} className="border-2 border-slate-100 px-8 py-4 rounded-2xl font-black text-slate-400 hover:text-slate-900 transition-all">返回首页</button>
                <button disabled={isDownloading} onClick={handleDownload} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black shadow-2xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">
                  {isDownloading ? '生成中...' : '下载高清证书'}
                </button>
              </div>
            </div>
            <div className="shadow-4xl rounded-[40px] border-8 border-slate-50 p-2 bg-white">
              <div className="scale-[0.4] sm:scale-[0.75] md:scale-95 lg:scale-100 origin-top">
                <Certificate data={selectedFinisher} style={style} innerRef={certificateRef} />
              </div>
            </div>
          </div>
        );

      default:
        setView('home');
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50/50 font-inter">
      {(view !== 'home' && view !== 'login' && view !== 'preview') && (
        <Header currentView={view} setView={setView} onLogout={() => { setIsAdmin(false); setView('home'); }} />
      )}
      <main className="flex-1">
        {renderMainContent()}
      </main>
      {(view === 'home' || isAdmin) && (
        <footer className="bg-white border-t border-slate-100 py-16 text-center no-print">
          <p className="text-slate-300 text-[10px] font-black uppercase tracking-[0.5em]">RunCertify Marathon Solutions</p>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import * as htmlToImage from 'html-to-image';
import Header from './components/Header';
import Certificate from './components/Certificate';
import { AppView, FinisherData, CertificateStyle } from './types';
import { generateInspirationalQuote, generateCustomBadge } from './geminiService';

const INITIAL_DATA: FinisherData[] = [
  {
    id: '1',
    name: '张杰瑞',
    bibNumber: 'A2045',
    raceName: '2024 城市马拉松',
    category: '全程马拉松 (42.195km)',
    finishTime: '03:45:21',
    netTime: '03:45:21',
    genderRank: '142 / 1200',
    overallRank: '312 / 4500',
    date: '2024年10月24日',
    inspirationalQuote: '奔跑是不设限的自由，脚步丈量的是勇气的疆域。',
  },
  {
    id: '2',
    name: '李安娜',
    bibNumber: 'B1088',
    raceName: '2024 城市马拉松',
    category: '半程马拉松 (21.0975km)',
    finishTime: '01:52:10',
    netTime: '01:51:45',
    genderRank: '85 / 800',
    overallRank: '520 / 3000',
    date: '2024年10月24日',
    inspirationalQuote: '每一次起跑，都是对平凡生活的一次超越。',
  }
];

const INITIAL_STYLE: CertificateStyle = {
  template: 'modern',
  primaryColor: '#4f46e5',
  secondaryColor: '#f59e0b',
  language: 'zh',
  orientation: 'landscape'
};

const App: React.FC = () => {
  // --- State ---
  const [isAdmin, setIsAdmin] = useState(false);
  const [view, setView] = useState<AppView>('home');
  const [finishers, setFinishers] = useState<FinisherData[]>(() => {
    const saved = localStorage.getItem('runcertify_records');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [selectedFinisher, setSelectedFinisher] = useState<FinisherData>(finishers[0] || INITIAL_DATA[0]);
  const [style, setStyle] = useState<CertificateStyle>(INITIAL_STYLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [badgeTheme, setBadgeTheme] = useState('金质立体勋章');
  const [searchError, setSearchError] = useState<string | null>(null);
  const [searchName, setSearchName] = useState('');

  // --- Refs ---
  const logoInputRef = useRef<HTMLInputElement>(null);
  const themeInputRef = useRef<HTMLInputElement>(null);
  const runnerInputRef = useRef<HTMLInputElement>(null);
  const certificateRef = useRef<HTMLDivElement>(null);

  // --- Persistence & Auth Guard ---
  useEffect(() => {
    localStorage.setItem('runcertify_records', JSON.stringify(finishers));
  }, [finishers]);

  useEffect(() => {
    // Safety check: Redirect if view requires admin but user isn't logged in
    if ((view === 'dashboard' || view === 'editor') && !isAdmin) {
      setView('login');
    }
  }, [view, isAdmin]);

  // --- Actions ---
  const handleSearch = () => {
    setSearchError(null);
    const query = searchName.trim();
    if (!query) {
      setSearchError('请输入姓名');
      return;
    }
    const found = finishers.find(f => f.name === query);
    if (found) {
      setSelectedFinisher(found);
      setView('search_result');
    } else {
      setSearchError('未找到相关记录，请核实姓名。');
    }
  };

  const handleSaveAndBack = () => {
    setFinishers(prev => {
      const idx = prev.findIndex(f => f.id === selectedFinisher.id);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = selectedFinisher;
        return next;
      }
      return [selectedFinisher, ...prev];
    });
    setView('dashboard');
  };

  const handleGenerateAI = async () => {
    if (!selectedFinisher.name) return;
    setIsGenerating(true);
    try {
      const [quote, badge] = await Promise.all([
        generateInspirationalQuote(selectedFinisher.name, selectedFinisher.category, selectedFinisher.finishTime, style.language),
        generateCustomBadge(badgeTheme)
      ]);
      setSelectedFinisher(prev => ({ 
        ...prev, 
        inspirationalQuote: quote, 
        badgeImageUrl: badge || prev.badgeImageUrl 
      }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const onFileUpload = (ref: React.RefObject<HTMLInputElement | null>, field: keyof FinisherData) => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedFinisher(prev => ({ ...prev, [field]: reader.result as string }));
        if (ref.current) ref.current.value = '';
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDownload = async () => {
    if (!certificateRef.current) return;
    setIsDownloading(true);
    try {
      const dataUrl = await htmlToImage.toPng(certificateRef.current, { pixelRatio: 2, cacheBust: true });
      const link = document.createElement('a');
      link.download = `Certificate_${selectedFinisher.name}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      alert('下载失败，请尝试在预览模式下手动截屏或稍后重试。');
    } finally {
      setIsDownloading(false);
    }
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(finishers, null, 2);
    const codeSnippet = `const INITIAL_DATA: FinisherData[] = ${dataStr};`;
    const blob = new Blob([codeSnippet], { type: 'text/javascript' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'database_snapshot.js';
    link.click();
    alert("【代码库存档包已生成】\n\n请将此文件中的代码覆盖回 App.tsx 的 INITIAL_DATA 处并重新部署。");
  };

  // --- Sub-Views ---
  const renderView = () => {
    switch (view) {
      case 'home':
        return (
          <div className="min-h-[90vh] flex flex-col items-center justify-center text-center px-6 bg-slate-900 relative overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-br from-indigo-900 via-slate-900 to-black"></div>
            <img src="https://images.unsplash.com/photo-1530541930197-ff16ac917b0e?auto=format&fit=crop&q=80&w=2000" className="absolute inset-0 w-full h-full object-cover opacity-20 mix-blend-overlay" />
            <div className="relative z-10 w-full max-w-4xl animate-in fade-in zoom-in-95 duration-700">
              <div className="inline-flex items-center gap-2 bg-white/10 px-4 py-2 rounded-full border border-white/20 mb-8 backdrop-blur-md">
                <span className="w-2 h-2 bg-indigo-500 rounded-full animate-pulse"></span>
                <span className="text-white/60 text-[10px] font-black uppercase tracking-widest">Official Verification System</span>
              </div>
              <h1 className="text-6xl sm:text-8xl font-black text-white mb-8 tracking-tighter leading-none">
                RunCertify<br/>
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-emerald-400">成就查询中心</span>
              </h1>
              <div className="max-w-xl mx-auto flex flex-col sm:flex-row gap-4 bg-white/10 p-2.5 rounded-[32px] backdrop-blur-2xl border border-white/20 shadow-2xl">
                <input 
                  type="text" 
                  placeholder="请输入您的参赛姓名" 
                  value={searchName}
                  onChange={(e) => setSearchName(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                  className="flex-1 bg-transparent px-8 py-4 text-white font-bold outline-none text-xl placeholder:text-white/30"
                />
                <button onClick={handleSearch} className="bg-white text-indigo-950 font-black px-12 py-4 rounded-[24px] hover:bg-indigo-50 transition-all shadow-xl active:scale-95">查询记录</button>
              </div>
              {searchError && <p className="mt-6 text-red-400 font-bold animate-pulse">{searchError}</p>}
            </div>
            <button onClick={() => setView('login')} className="absolute bottom-12 text-white/30 hover:text-white font-black text-[10px] tracking-[0.3em] uppercase transition-colors">Admin Panel Access</button>
          </div>
        );

      case 'login':
        return (
          <div className="min-h-screen flex items-center justify-center bg-slate-950 px-6">
             <div className="w-full max-w-md bg-white rounded-[48px] p-12 shadow-3xl">
              <div className="text-center mb-10">
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">后台安全验证</h2>
                <p className="text-slate-400 font-medium mt-1">请输入管理员授权凭据</p>
              </div>
              <form className="space-y-6" onSubmit={(e) => {
                e.preventDefault();
                const formData = new FormData(e.currentTarget);
                if (formData.get('account') === '13866668888' && formData.get('password') === '123456') {
                  setIsAdmin(true); setView('dashboard');
                } else {
                  alert('验证未通过');
                }
              }}>
                <div className="space-y-4">
                  <input name="account" type="text" placeholder="管理账号" className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4.5 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                  <input name="password" type="password" placeholder="授权密码" className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4.5 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                </div>
                <button type="submit" className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-2xl hover:bg-indigo-700 transition-all active:scale-[0.98]">进入控制台</button>
                <button type="button" onClick={() => setView('home')} className="w-full text-slate-400 font-bold text-xs uppercase tracking-widest hover:text-slate-900 transition-colors">返回门户首页</button>
              </form>
            </div>
          </div>
        );

      case 'dashboard':
        return (
          <div className="max-w-7xl mx-auto px-6 py-16 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col md:flex-row justify-between items-end mb-16 gap-8">
              <div>
                <h1 className="text-5xl font-black text-slate-900 tracking-tighter leading-none">成绩记录库</h1>
                <p className="text-slate-500 font-medium mt-4">管理并配置选手的完赛成绩。更新后请导出快照更新代码库。</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button onClick={handleExportData} className="flex-1 md:flex-none border-2 border-slate-200 px-8 py-4 rounded-[22px] font-bold hover:bg-slate-50 transition-all">导出代码存档</button>
                <button onClick={() => {
                  setSelectedFinisher({...INITIAL_DATA[0], id: Math.random().toString(36).substr(2, 9), name: '', category: ''});
                  setView('editor');
                }} className="flex-1 md:flex-none bg-indigo-600 text-white px-10 py-4 rounded-[22px] font-black shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">录入新选手</button>
              </div>
            </div>
            <div className="bg-white rounded-[40px] shadow-2xl border border-slate-100 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-100">
                  <tr>
                    <th className="px-10 py-7 text-[11px] font-black text-slate-400 uppercase tracking-widest">选手全名</th>
                    <th className="px-10 py-7 text-[11px] font-black text-slate-400 uppercase tracking-widest">参赛项目 / 号码</th>
                    <th className="px-10 py-7 text-[11px] font-black text-slate-400 uppercase tracking-widest">完赛成绩</th>
                    <th className="px-10 py-7 text-[11px] font-black text-slate-400 uppercase tracking-widest text-right">管理操作</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {finishers.map(f => (
                    <tr key={f.id} className="hover:bg-slate-50/50 transition-all group">
                      <td className="px-10 py-8">
                        <div className="font-black text-slate-900 text-lg group-hover:text-indigo-600 transition-colors">{f.name || '未填'}</div>
                        <div className="text-[11px] text-slate-400 font-bold uppercase tracking-wider mt-1">{f.raceName}</div>
                      </td>
                      <td className="px-10 py-8">
                        <div className="text-xs font-bold text-slate-600 mb-1">{f.category || '未指定项目'}</div>
                        <span className="bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-xl font-mono font-black border border-indigo-100/50">{f.bibNumber}</span>
                      </td>
                      <td className="px-10 py-8 font-black text-slate-900 text-lg tabular-nums">{f.finishTime}</td>
                      <td className="px-10 py-8 text-right">
                        <button onClick={() => { setSelectedFinisher(f); setView('editor'); }} className="text-[11px] font-black text-indigo-600 hover:text-indigo-800 transition-colors uppercase tracking-widest border-b-2 border-indigo-100 hover:border-indigo-600">编辑证书</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );

      case 'editor':
        return (
          <div className="min-h-screen bg-slate-50/50">
            <div className="max-w-[1600px] mx-auto px-6 py-10">
              <div className="flex flex-col xl:flex-row gap-10">
                {/* 侧边控制面板 */}
                <div className="w-full xl:w-[480px] shrink-0 space-y-8 animate-in slide-in-from-left-4 duration-500">
                  <div className="bg-white p-10 rounded-[48px] shadow-2xl border border-slate-100">
                    <h3 className="text-2xl font-black tracking-tight text-slate-900 mb-8">选手与项目配置</h3>
                    <div className="space-y-5">
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">选手姓名</label>
                          <input type="text" value={selectedFinisher.name} onChange={e => setSelectedFinisher({...selectedFinisher, name: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                        </div>
                        <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">参赛号码</label>
                          <input type="text" value={selectedFinisher.bibNumber} onChange={e => setSelectedFinisher({...selectedFinisher, bibNumber: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                        </div>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">参赛项目 (Category)</label>
                        <input type="text" value={selectedFinisher.category} onChange={e => setSelectedFinisher({...selectedFinisher, category: e.target.value})} placeholder="例如: 全程马拉松 (42.195km)" className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">赛事名称</label>
                        <input type="text" value={selectedFinisher.raceName} onChange={e => setSelectedFinisher({...selectedFinisher, raceName: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">完赛成绩</label>
                          <input type="text" value={selectedFinisher.finishTime} onChange={e => setSelectedFinisher({...selectedFinisher, finishTime: e.target.value, netTime: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                        </div>
                        <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">全场排名</label>
                          <input type="text" value={selectedFinisher.overallRank} onChange={e => setSelectedFinisher({...selectedFinisher, overallRank: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-50 rounded-2xl px-6 py-4 font-bold outline-none focus:border-indigo-600 focus:bg-white transition-all" />
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="bg-indigo-600 p-10 rounded-[48px] text-white space-y-6 shadow-2xl shadow-indigo-100">
                    <h3 className="text-xl font-black italic tracking-tight">Gemini AI 智能加持</h3>
                    <div className="space-y-4">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-indigo-200 uppercase tracking-[0.2em] ml-1">勋章风格关键词</label>
                        <input type="text" value={badgeTheme} onChange={e => setBadgeTheme(e.target.value)} className="w-full bg-white/10 border border-white/20 rounded-2xl px-6 py-4 text-sm font-bold outline-none focus:bg-white/20" />
                      </div>
                      <button disabled={isGenerating || !selectedFinisher.name} onClick={handleGenerateAI} className={`w-full py-5 rounded-2xl font-black text-sm transition-all shadow-xl ${isGenerating ? 'bg-white/20 cursor-wait' : 'bg-white text-indigo-700 hover:scale-[1.02] active:scale-95'}`}>
                        {isGenerating ? 'AI 正在创作中...' : '生成智能名言与勋章'}
                      </button>
                    </div>
                  </div>

                  <div className="bg-white p-10 rounded-[48px] shadow-2xl border border-slate-100 space-y-8">
                    <h3 className="text-xl font-black text-slate-900">视觉与样式定义</h3>
                    <div className="space-y-6">
                      <div className="grid grid-cols-2 gap-3">
                        <button onClick={() => setStyle({...style, orientation: 'landscape'})} className={`py-4 rounded-2xl font-black text-xs uppercase tracking-widest border-2 transition-all ${style.orientation === 'landscape' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>横向板式</button>
                        <button onClick={() => setStyle({...style, orientation: 'portrait'})} className={`py-4 rounded-2xl font-black text-xs uppercase tracking-widest border-2 transition-all ${style.orientation === 'portrait' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>纵向板式</button>
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                        {['classic', 'modern', 'minimal', 'energetic'].map(t => (
                          <button key={t} onClick={() => setStyle({...style, template: t as any})} className={`py-4 rounded-2xl font-black text-[10px] border-2 uppercase tracking-widest transition-all ${style.template === t ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>{t}</button>
                        ))}
                      </div>
                      <div className="grid grid-cols-3 gap-3">
                        <button onClick={() => logoInputRef.current?.click()} className="py-4 bg-slate-50 hover:bg-slate-100 rounded-2xl flex flex-col items-center justify-center gap-2 border border-transparent transition-all">
                           <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M4 16v1a3 3 0 0 0 3 3h10a3 3 0 0 0 3-3v-1m-4-8-4-4m0 0L8 8m4-4v12"/></svg>
                           <span className="text-[8px] font-black uppercase tracking-widest">Logo</span>
                        </button>
                        <button onClick={() => themeInputRef.current?.click()} className="py-4 bg-slate-50 hover:bg-slate-100 rounded-2xl flex flex-col items-center justify-center gap-2 border border-transparent transition-all">
                           <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
                           <span className="text-[8px] font-black uppercase tracking-widest">背景</span>
                        </button>
                        <button onClick={() => runnerInputRef.current?.click()} className="py-4 bg-slate-50 hover:bg-slate-100 rounded-2xl flex flex-col items-center justify-center gap-2 border border-transparent transition-all">
                           <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>
                           <span className="text-[8px] font-black uppercase tracking-widest">照片</span>
                        </button>
                      </div>
                    </div>
                  </div>
                  <input ref={logoInputRef} type="file" accept="image/*" onChange={onFileUpload(logoInputRef, 'logoUrl')} className="hidden" />
                  <input ref={themeInputRef} type="file" accept="image/*" onChange={onFileUpload(themeInputRef, 'themeImageUrl')} className="hidden" />
                  <input ref={runnerInputRef} type="file" accept="image/*" onChange={onFileUpload(runnerInputRef, 'runnerImageUrl')} className="hidden" />
                </div>

                {/* 主预览区域 */}
                <div className="flex-1 flex flex-col items-center animate-in fade-in zoom-in-95 duration-700">
                  <div className="w-full bg-white p-12 xl:p-20 rounded-[64px] shadow-[0_48px_100px_-20px_rgba(0,0,0,0.12)] border border-slate-100 flex items-center justify-center min-h-[600px] overflow-hidden relative">
                    <div className="transform scale-[0.45] sm:scale-[0.8] lg:scale-[0.9] xl:scale-100 2xl:scale-110 transition-all duration-500 origin-center drop-shadow-2xl">
                      <Certificate data={selectedFinisher} style={style} innerRef={certificateRef} />
                    </div>
                  </div>
                  <div className="mt-16 flex flex-col sm:flex-row gap-6 w-full max-w-2xl px-6">
                    <button onClick={() => setView('preview')} className="flex-1 px-14 py-5 bg-slate-900 text-white font-black rounded-3xl shadow-2xl hover:bg-black transition-all text-sm tracking-widest uppercase">全屏沉浸预览</button>
                    <button onClick={handleSaveAndBack} className="flex-1 px-14 py-5 bg-indigo-600 text-white font-black rounded-3xl shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all text-sm tracking-widest uppercase">确认保存修改</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );

      case 'search_result':
        return (
          <div className="min-h-screen bg-white flex flex-col items-center p-10 sm:p-24 animate-in fade-in duration-1000">
            <div className="w-full max-w-6xl flex flex-col xl:flex-row justify-between items-center mb-20 gap-12">
              <div className="text-center xl:text-left">
                <h1 className="text-6xl sm:text-8xl font-black text-slate-900 mb-4 tracking-tighter leading-none italic">VICTORY.</h1>
                <p className="text-slate-400 font-black tracking-[0.3em] uppercase text-sm">官方已核验完赛选手: <span className="text-slate-900 border-b-4 border-indigo-600 ml-2">{selectedFinisher.name}</span></p>
              </div>
              <div className="flex gap-4 w-full sm:w-auto">
                <button onClick={() => setView('home')} className="flex-1 sm:flex-none border-2 border-slate-100 px-10 py-5 rounded-[28px] font-black text-slate-400 hover:text-slate-900 transition-all uppercase text-xs tracking-widest">返回主页</button>
                <button disabled={isDownloading} onClick={handleDownload} className="flex-1 sm:flex-none bg-indigo-600 text-white px-12 py-5 rounded-[28px] font-black shadow-2xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 uppercase text-xs tracking-widest">
                  {isDownloading ? '生成高精度版...' : '下载高清电子证书'}
                </button>
              </div>
            </div>
            <div className="shadow-2xl rounded-[56px] border-8 border-slate-50 p-2 bg-white">
              <div className="scale-[0.4] sm:scale-[0.7] md:scale-95 lg:scale-100 origin-top">
                <Certificate data={selectedFinisher} style={style} innerRef={certificateRef} />
              </div>
            </div>
          </div>
        );

      case 'preview':
        return (
          <div className="min-h-screen bg-slate-950 flex flex-col items-center p-12">
            <div className="w-full max-w-6xl flex flex-col sm:flex-row justify-between items-center mb-16 no-print gap-8">
              <button onClick={() => setView(isAdmin ? 'editor' : 'search_result')} className="bg-white/10 hover:bg-white/20 text-white px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest transition-all">返回修改</button>
              <button onClick={() => window.print()} className="bg-white text-slate-950 px-12 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:scale-105 active:scale-95 transition-all">确认并打印证书</button>
            </div>
            <div className="bg-white p-1 rounded-2xl shadow-4xl scale-[0.5] sm:scale-[0.85] md:scale-100 xl:scale-125 origin-top transition-transform duration-700">
              <Certificate data={selectedFinisher} style={style} />
            </div>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50/10 font-inter selection:bg-indigo-100">
      {(view !== 'home' && view !== 'login' && view !== 'preview') && (
        <Header currentView={view} setView={setView} onLogout={() => { setIsAdmin(false); setView('home'); }} />
      )}
      <main className="flex-1">
        {renderView()}
      </main>
      {(view === 'home' || isAdmin) && (
        <footer className="bg-white border-t border-slate-100 py-20 text-center no-print">
          <div className="max-w-xl mx-auto px-6">
            <p className="text-slate-300 text-[10px] font-black uppercase tracking-[0.5em] mb-4">RunCertify Marathon Technology</p>
            <div className="w-12 h-1.5 bg-indigo-50 mx-auto rounded-full mb-8"></div>
            <p className="text-slate-400 text-xs font-medium leading-relaxed">
              专业级马拉松完赛成就管理系统。为赛事组织者提供安全、智能、美观的数字化完赛证明服务。
            </p>
          </div>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
