    bibNumber: 'B1088',
    raceName: '2024 城市马拉松',
    category: '半程马拉松 (21.0975km)',
    finishTime: '01:52:10',
    netTime: '01:51:45',
    genderRank: '85 / 800',
    overallRank: '520 / 3000',
