                          <button key={t} onClick={() => setStyle({...style, template: t as any})} className={`py-4 rounded-2xl font-black text-[10px] border-2 uppercase tracking-widest transition-all ${style.template === t ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-50 bg-slate-50 text-slate-400'}`}>{t}</button>
